      ]
    }));
  }
  rows.forEach(([c1, c2, bg1, bg2, bold1]) => {
    tableRows.push(new TableRow({
      children: [
        new TableCell({ borders, width: { size: colW[0], type: WidthType.DXA }, shading: { fill: bg1 || WHITE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: c1, bold: !!bold1, size: 19, font: "Arial" })] })] }),
        new TableCell({ borders, width: { size: colW[1], type: WidthType.DXA }, shading: { fill: bg2 || WHITE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: c2, size: 19, font: "Arial" })] })] }),
      ]
    }));
  });
  return new Table({ width: { size: W, type: WidthType.DXA }, columnWidths: colW, rows: tableRows });
}

// 3-col table
function table3(rows, colW = [2800, 3280, 3280], hdrRow = null) {
