    new TableCell({
      borders,
      width: { size: colW[0], type: WidthType.DXA },
      shading: { fill: bg || WHITE, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      children: [new Paragraph({ alignment: align || AlignmentType.LEFT, children: [new TextRun({ text, bold: !!bold, size: 19, font: "Arial" })] })]
    });
  const tableRows = [];
  if (hdrRow) {
    tableRows.push(new TableRow({
      tableHeader: true,
      children: hdrRow.map((h, i) =>
        new TableCell({ borders, width: { size: colW[i], type: WidthType.DXA }, shading: { fill: BLUE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
          children: [new Paragraph({ children: [new TextRun({ text: h, bold: true, size: 20, font: "Arial", color: WHITE })] })] })
      )
    }));
  }
  rows.forEach(r => {
    tableRows.push(new TableRow({
      children: r.map((cell, i) => {
        const txt   = typeof cell === 'string' ? cell : cell.text;
        const bg    = typeof cell === 'object' ? cell.bg    : null;
        const bold  = typeof cell === 'object' ? cell.bold  : false;
        const align = typeof cell === 'object' ? cell.align : null;
        return new TableCell({ borders, width: { size: colW[i], type: WidthType.DXA }, shading: { fill: bg || WHITE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
          children: [new Paragraph({ alignment: align, children: [new TextRun({ text: txt, bold: !!bold, size: 19, font: "Arial" })] })] });
      })
    }));
  });
  return new Table({ width: { size: W, type: WidthType.DXA }, columnWidths: colW, rows: tableRows });
}

function callout(title, body, bg, titleColor) {
  return new Table({
    width: { size: W, type: WidthType.DXA },
    columnWidths: [W],
    rows: [new TableRow({ children: [
      new TableCell({
