        shading: { fill: bg, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 180, right: 180 },
        children: [
          new Paragraph({ spacing: { after: 60 }, children: [new TextRun({ text: title, bold: true, size: 20, font: "Arial", color: titleColor })] }),
          new Paragraph({ spacing: { before: 0 }, children: [new TextRun({ text: body, size: 19, font: "Arial" })] }),
        ]
      })
    ]})]
  });
}

