{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, PageBreak
} = require('docx');
const fs = require('fs');

const BLUE      = "1F4E79";
const BLUE_MID  = "2E75B6";
const BLUE_LIGHT= "D6E4F0";
const BLUE_HDR  = "BDD7EE";
const GREEN_BG  = "E2EFDA";
const RED_BG    = "FCE4D6";
const AMBER_BG  = "FFF2CC";
const INFO_BG   = "DEEAF1";
const GRAY_BG   = "F2F2F2";
const WHITE     = "FFFFFF";

const border1 = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders  = { top: border1, bottom: border1, left: border1, right: border1 };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders= { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

const W = 9360; // content width US Letter 1" margins

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 320, after: 160 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: BLUE_MID, space: 1 } },
    children: [new TextRun({ text, bold: true, size: 28, color: BLUE, font: "Arial" })]
  });
}
function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 120 },
    children: [new TextRun({ text, bold: true, size: 24, color: BLUE_MID, font: "Arial" })]
  });
}
function h3(text) {
  return new Paragraph({
    spacing: { before: 180, after: 80 },
    children: [new TextRun({ text, bold: true, size: 22, color: "404040", font: "Arial" })]
  });
}
function p(text, opts = {}) {
  return new Paragraph({
    spacing: { before: 60, after: 80 },
    children: [new TextRun({ text, size: 20, font: "Arial", ...opts })]
  });
}
function pRuns(runs) {
  return new Paragraph({
    spacing: { before: 60, after: 80 },
    children: runs.map(r => new TextRun({ size: 20, font: "Arial", ...r }))
  });
}
function bullet(text, bold = false) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, size: 20, font: "Arial", bold })]
  });
}
function space(sz = 120) {
  return new Paragraph({ spacing: { before: sz, after: 0 }, children: [new TextRun("")] });
}
function mono(text) {
  return new TextRun({ text, font: "Courier New", size: 18, color: "1A237E" });
}

// Simple 2-col table helper
function table2(rows, colW = [3200, 6160], hdrRow = null) {
  const mkCell = (text, bg, bold = false, isHdr = false) =>
    new TableCell({
      borders,
      width: { size: colW[0], type: WidthType.DXA },
      shading: { fill: bg, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      children: [new Paragraph({ children: [new TextRun({ text, bold: bold || isHdr, size: isHdr ? 20 : 19, font: "Arial", color: isHdr ? WHITE : "000000" })] })]
    });
  const tableRows = [];
  if (hdrRow) {
    tableRows.push(new TableRow({
      tableHeader: true,
