        new TableCell({ borders, width: { size: colW[0], type: WidthType.DXA }, shading: { fill: BLUE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: hdrRow[0], bold: true, size: 20, font: "Arial", color: WHITE })] })] }),
        new TableCell({ borders, width: { size: colW[1], type: WidthType.DXA }, shading: { fill: BLUE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: hdrRow[1], bold: true, size: 20, font: "Arial", color: WHITE })] })] }),
      ]
    }));
  }
