     1	//+------------------------------------------------------------------+
     2	//|                                          ORB_BreakoutEA_v1.mq5  |
     3	//|                    Opening Range Breakout Expert Advisor v1.00   |
     4	//|                              Jose's Trading Suite - Abril 2025   |
     5	//+------------------------------------------------------------------+
     6	//|  DESCRIPCION:                                                    |
     7	//|  EA basado en el concepto Opening Range Breakout (ORB).          |
     8	//|  Define el rango de las primeras N velas de sesion y coloca      |
     9	//|  ordenes pendientes en sus extremos. Al activarse una direccion, |
    10	//|  la opuesta se cancela automaticamente. Gestion de riesgo        |
    11	//|  integrada por USD o % del balance.                              |
    12	//|                                                                  |
    13	//|  NOTA PIP: 1 pip = 10 puntos (brokers modernos 5/3/2 decimales) |
    14	//|  Para XAUUSD 2 decimales: pip = $0.10 en precio.                 |
    15	//|  SL=50 pips en gold = $5.00 de movimiento de precio.             |
    16	//+------------------------------------------------------------------+
    17	#property copyright   "Jose's Trading Suite"
    18	#property link        ""
    19	#property version     "1.00"
    20	#property description "Opening Range Breakout EA - Opera una sola vez al dia"
    21	
    22	#include <Trade\Trade.mqh>
    23	
    24	//+------------------------------------------------------------------+
    25	//|  PARAMETROS DE ENTRADA                                           |
    26	//+------------------------------------------------------------------+
    27	
    28	input group "=== CONFIGURACION DEL RANGO ORB ==="
    29	input int     InpRangeCandles    = 3;           // Numero de velas del rango inicial
    30	input int     InpSessionHour     = 9;           // Hora inicio sesion (hora servidor GMT)
    31	input int     InpSessionMinute   = 0;           // Minutos inicio sesion
    32	
    33	input group "=== GESTION DE RIESGO ==="
    34	input double  InpTP_Pips         = 100.0;       // Take Profit (pips)
    35	input double  InpSL_Pips         = 50.0;        // Stop Loss (pips)
    36	input double  InpBE_Pips         = 50.0;        // Breakeven trigger (pips, 0 = desactivado)
    37	input double  InpRiskUSD         = 50.0;        // Riesgo en USD por operacion
    38	input bool    InpUsePercentRisk  = false;        // Usar % del balance en lugar de USD
    39	input double  InpRiskPercent     = 1.0;         // Riesgo en % si UsePercentRisk = true
    40	
    41	input group "=== DIAS PERMITIDOS ==="
    42	input bool    InpAllowMonday     = true;         // Lunes
    43	input bool    InpAllowTuesday    = true;         // Martes
    44	input bool    InpAllowWednesday  = true;         // Miercoles
    45	input bool    InpAllowThursday   = true;         // Jueves
    46	input bool    InpAllowFriday     = true;         // Viernes
    47	input bool    InpAllowSaturday   = false;        // Sabado
    48	input bool    InpAllowSunday     = false;        // Domingo
    49	
    50	input group "=== CONFIGURACION GENERAL ==="
    51	input bool    InpOnlyOnePerDay   = true;         // Solo un trade por dia (false = re-entrada tras cierre)
    52	input int     InpMagicNumber     = 20250403;     // Magic Number unico del EA
    53	input string  InpComment         = "ORB_EA";     // Comentario de las ordenes
    54	
    55	
    56	//+------------------------------------------------------------------+
    57	//|  VARIABLES GLOBALES                                              |
    58	//+------------------------------------------------------------------+
    59	
    60	CTrade   g_Trade;
    61	
    62	// Configuracion
    63	double   g_PipSize        = 0.0;
    64	
    65	// Control de dia
    66	int      g_PrevDay        = -1;
    67	
    68	// Estado de la logica diaria
    69	bool     g_RangeBuilt     = false;   // Rango ORB completamente definido
    70	bool     g_OrdersPlaced   = false;   // Ordenes pendientes activas en el mercado
    71	bool     g_TradeDone      = false;   // Actividad del dia terminada
    72	bool     g_BEApplied      = false;   // Breakeven ya fue aplicado
    73	bool     g_OppCancelled   = false;   // Se cancelo la orden opuesta (posicion activa)
    74	
    75	// Niveles del rango
    76	double   g_RangeHigh      = 0.0;
    77	double   g_RangeLow       = 0.0;
    78	
    79	// Tiempos de la sesion
    80	datetime g_RangeStartTime = 0;
    81	datetime g_RangeEndTime   = 0;
    82	
    83	// Tickets de las ordenes pendientes
    84	ulong    g_TicketBuy      = 0;
    85	ulong    g_TicketSell     = 0;
    86	
    87	
    88	//+------------------------------------------------------------------+
    89	//| OnInit - Inicializacion del EA                                   |
    90	//+------------------------------------------------------------------+
    91	int OnInit()
    92	{
    93	   //--- Validar parametros de entrada
    94	   if(InpRangeCandles < 1)
    95	   {
    96	      Alert("Error: InpRangeCandles debe ser >= 1");
    97	      return INIT_PARAMETERS_INCORRECT;
    98	   }
    99	   if(InpSL_Pips <= 0.0 || InpTP_Pips <= 0.0)
   100	   {
   101	      Alert("Error: SL y TP deben ser > 0 pips");
   102	      return INIT_PARAMETERS_INCORRECT;
   103	   }
   104	   if(!InpUsePercentRisk && InpRiskUSD <= 0.0)
   105	   {
   106	      Alert("Error: InpRiskUSD debe ser > 0");
   107	      return INIT_PARAMETERS_INCORRECT;
   108	   }
   109	   if(InpUsePercentRisk && (InpRiskPercent <= 0.0 || InpRiskPercent > 20.0))
   110	   {
   111	      Alert("Error: InpRiskPercent debe estar entre 0.1 y 20.0");
   112	      return INIT_PARAMETERS_INCORRECT;
   113	   }
   114	   if(InpSessionHour < 0 || InpSessionHour > 23)
   115	   {
   116	      Alert("Error: InpSessionHour debe ser entre 0 y 23");
   117	      return INIT_PARAMETERS_INCORRECT;
   118	   }
   119	   if(InpSessionMinute < 0 || InpSessionMinute > 59)
   120	   {
   121	      Alert("Error: InpSessionMinute debe ser entre 0 y 59");
   122	      return INIT_PARAMETERS_INCORRECT;
   123	   }
   124	
   125	   //--- Configurar objeto de trade
   126	   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   127	   g_Trade.SetDeviationInPoints(30);
   128	   g_Trade.SetAsyncMode(false);
   129	   g_Trade.SetTypeFilling(DetectFillingType());
   130	
   131	   //--- Calcular tamano del pip
   132	   // Convencion moderna: 1 pip = 10 * _Point
   133	   // Valido para: EURUSD 5-dig, USDJPY 3-dig, XAUUSD 2/3-dig, indices, etc.
   134	   g_PipSize = _Point * 10.0;
   135	
   136	   //--- Log de inicializacion
   137	   Print("═══════════════════════════════════════════");
   138	   Print("     ORB BREAKOUT EA v1.00 - Iniciando     ");
   139	   Print("═══════════════════════════════════════════");
   140	   PrintFormat("  Simbolo    : %s  |  TF: %s",   _Symbol, EnumToString(_Period));
   141	   PrintFormat("  Digits     : %d  |  Point: %.5f  |  PipSize: %.5f", _Digits, _Point, g_PipSize);
   142	   PrintFormat("  Sesion     : %02d:%02d  |  Rango: %d velas", InpSessionHour, InpSessionMinute, InpRangeCandles);
   143	   PrintFormat("  SL=%.1f | TP=%.1f | BE=%.1f  (pips)", InpSL_Pips, InpTP_Pips, InpBE_Pips);
   144	   PrintFormat("  Riesgo     : %s", InpUsePercentRisk
   145	               ? StringFormat("%.2f%% del balance", InpRiskPercent)
   146	               : StringFormat("$%.2f fijo", InpRiskUSD));
   147	   PrintFormat("  Magic #    : %d  |  OnlyOnePerDay: %s", InpMagicNumber, (string)InpOnlyOnePerDay);
   148	   Print("═══════════════════════════════════════════");
   149	
   150	   return INIT_SUCCEEDED;
   151	}
   152	
   153	
   154	//+------------------------------------------------------------------+
   155	//| OnDeinit - Limpieza al remover el EA                            |
   156	//+------------------------------------------------------------------+
   157	void OnDeinit(const int reason)
   158	{
   159	   CancelAllPendingOrders();
   160	   Comment("");
   161	   PrintFormat("ORB EA detenido. Razon: %d", reason);
   162	}
   163	
   164	
   165	//+------------------------------------------------------------------+
   166	//| OnTick - Logica principal ejecutada en cada tick                |
   167	//+------------------------------------------------------------------+
   168	void OnTick()
   169	{
   170	   datetime     now = TimeCurrent();
   171	   MqlDateTime  dt;
   172	   TimeToStruct(now, dt);
   173	
   174	   //--- Detectar nuevo dia y reiniciar estado
   175	   if(dt.day != g_PrevDay)
   176	   {
   177	      ResetDay(now, dt.day_of_week);
   178	      g_PrevDay = dt.day;
   179	   }
   180	
   181	   //--- Filtro por dia de la semana
   182	   if(!IsDayAllowed(dt.day_of_week))
   183	   {
   184	      UpdatePanel("DIA NO PERMITIDO");
   185	      return;
   186	   }
   187	
   188	   //--- Si ya terminamos la actividad del dia, no hacer nada
   189	   if(g_TradeDone)
   190	   {
   191	      UpdatePanel("COMPLETADO");
   192	      return;
   193	   }
   194	
   195	   // ──────────────────────────────────────────────────
   196	   // FASE 1: Esperar a que se complete la ventana
