//+------------------------------------------------------------------+
//| CalculateLotSize - Calcula el lotaje basado en el riesgo        |
//|                    definido (USD o % del balance)                |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk
                       ? (balance * InpRiskPercent / 100.0)
                       : InpRiskUSD;

   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickValue <= 0.0)
   {
      PrintFormat("CalculateLotSize: tick info invalida (tickValue=%.5f tickSize=%.5f)",
                  tickValue, tickSize);
      return 0.0;
   }

   // Valor monetario por pip por lote estandar (en divisa de la cuenta)
   double valuePerPip = tickValue * (g_PipSize / tickSize);
   if(valuePerPip <= 0.0) return 0.0;

   // Formula: Lots = Riesgo$ / (SL_pips * $/pip/lot)
   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   // Redondear hacia abajo al step mas cercano
   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   PrintFormat("Lotaje calculado: %.2f  (Riesgo=$%.2f | $/pip=$%.4f | Balance=$%.2f)",
               lots, riskAmount, valuePerPip, balance);
   return lots;
}


