//+------------------------------------------------------------------+
//| BuildRange - Escanea el historial de velas dentro de la ventana |
//|              de sesion y extrae el High y Low del rango ORB      |
//+------------------------------------------------------------------+
bool BuildRange()
{
   double  hi    = 0.0;
   double  lo    = DBL_MAX;
   int     count = 0;
   int     total = iBars(_Symbol, _Period);

   // Recorrer desde la vela cerrada mas reciente hacia atras (i=0 esta en formacion)
   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);

      if(t >= g_RangeEndTime)   continue;  // Vela posterior al rango → ignorar
      if(t < g_RangeStartTime)  break;     // Vela anterior a la sesion → salir del loop

      double barHi = iHigh(_Symbol, _Period, i);
      double barLo = iLow (_Symbol, _Period, i);

      if(barHi > hi) hi = barHi;
      if(barLo < lo) lo = barLo;
      count++;
   }

   PrintFormat("BuildRange: %d vela(s) procesada(s) en [%s - %s]",
               count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));

   if(count == 0 || hi <= lo || hi == 0.0)
      return false;

   g_RangeHigh = hi;
   g_RangeLow  = lo;
   return true;
}


//+------------------------------------------------------------------+
//| PlacePendingOrders - Coloca BUY STOP en el High y SELL STOP en  |
//|                      el Low del rango ORB                        |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   double ask      = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid      = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist   = InpSL_Pips * g_PipSize;
   double tpDist   = InpTP_Pips * g_PipSize;
   // Distancia minima requerida por el broker para ordenes pendientes
   double minDist  = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots     = CalculateLotSize();
   bool   placed   = false;

   if(lots <= 0.0)
   {
      Print("PlacePendingOrders: lotaje invalido calculado. Saltando dia.");
      g_TradeDone = true;
      return;
   }

   // ─── BUY STOP en el High del rango ──────────────────────────
   // Solo si el precio actual esta lo suficientemente por debajo del High
   if(g_RangeHigh > ask + minDist)
   {
      double entry = NormalizeDouble(g_RangeHigh, _Digits);
      double sl    = NormalizeDouble(entry - slDist, _Digits);
      double tp    = NormalizeDouble(entry + tpDist, _Digits);

      if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketBuy = g_Trade.ResultOrder();
         Print("BUY STOP colocado | #", (string)g_TicketBuy,
               "  E=", DoubleToString(entry, _Digits),
               "  SL=", DoubleToString(sl, _Digits),
               "  TP=", DoubleToString(tp, _Digits),
               "  Lots=", DoubleToString(lots, 2));
         placed = true;
      }
      else
      {
         PrintFormat("Error BUY STOP: %s  Codigo: %d",
                     g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
   }
   else
   {
      PrintFormat("BUY STOP omitido: ask=%.5f demasiado cerca del High=%.5f  (minDist=%.5f)",
                  ask, g_RangeHigh, minDist);
   }

   // ─── SELL STOP en el Low del rango ──────────────────────────
   // Solo si el precio actual esta lo suficientemente por encima del Low
   if(g_RangeLow < bid - minDist)
   {
      double entry = NormalizeDouble(g_RangeLow, _Digits);
      double sl    = NormalizeDouble(entry + slDist, _Digits);
      double tp    = NormalizeDouble(entry - tpDist, _Digits);

      if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketSell = g_Trade.ResultOrder();
         Print("SELL STOP colocado | #", (string)g_TicketSell,
               "  E=", DoubleToString(entry, _Digits),
               "  SL=", DoubleToString(sl, _Digits),
               "  TP=", DoubleToString(tp, _Digits),
               "  Lots=", DoubleToString(lots, 2));
         placed = true;
      }
      else
      {
         PrintFormat("Error SELL STOP: %s  Codigo: %d",
                     g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
   }
   else
   {
      PrintFormat("SELL STOP omitido: bid=%.5f demasiado cerca del Low=%.5f  (minDist=%.5f)",
                  bid, g_RangeLow, minDist);
   }

   g_OrdersPlaced = placed;

   if(!placed)
   {
      Print("Sin ordenes colocadas. El precio ya esta fuera del rango. Dia terminado.");
      g_TradeDone = true;
   }
}


//+------------------------------------------------------------------+
//| ManageTrade - Logica de gestion: detecta activacion, cancela    |
//|               la orden opuesta y aplica Breakeven               |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();

