//+------------------------------------------------------------------+
//| CreateHLine — crea linea horizontal en el grafico               |
//+------------------------------------------------------------------+
void CreateHLine(string name, double price, color clr, int width, ENUM_LINE_STYLE style, string labelText)
{
   if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);

   ObjectCreate(0, name, OBJ_HLINE, 0, 0, price);
   ObjectSetInteger(0, name, OBJPROP_COLOR,    clr);
   ObjectSetInteger(0, name, OBJPROP_WIDTH,    width);
   ObjectSetInteger(0, name, OBJPROP_STYLE,    style);
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_HIDDEN,   true);

   // Etiqueta de precio al lado derecho
   string lblName = name + "_lbl";
   if(ObjectFind(0, lblName) >= 0) ObjectDelete(0, lblName);
   ObjectCreate(0, lblName, OBJ_TEXT, 0, TimeCurrent() + PeriodSeconds(_Period) * 3, price);
   ObjectSetString(0,  lblName, OBJPROP_TEXT, " " + labelText + " " + DoubleToString(price, _Digits));
   ObjectSetInteger(0, lblName, OBJPROP_COLOR,    clr);
   ObjectSetInteger(0, lblName, OBJPROP_FONTSIZE, 9);
   ObjectSetInteger(0, lblName, OBJPROP_ANCHOR,   ANCHOR_LEFT);
   ObjectSetInteger(0, lblName, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, lblName, OBJPROP_HIDDEN,   true);
}

//+------------------------------------------------------------------+
//| DrawSessionLine — linea vertical punteada blanca en inicio      |
//+------------------------------------------------------------------+
void DrawSessionLine()
{
   string name = g_ObjPrefix + "SessionLine";
   if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);

   ObjectCreate(0, name, OBJ_VLINE, 0, g_RangeStartTime, 0);
   ObjectSetInteger(0, name, OBJPROP_COLOR,      InpColorSession);
   ObjectSetInteger(0, name, OBJPROP_STYLE,      STYLE_DOT);
   ObjectSetInteger(0, name, OBJPROP_WIDTH,      1);
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_HIDDEN,     true);

   // Etiqueta de hora de sesion
   string lblName = g_ObjPrefix + "SessionLabel";
   if(ObjectFind(0, lblName) >= 0) ObjectDelete(0, lblName);
   ObjectCreate(0, lblName, OBJ_TEXT, 0, g_RangeStartTime, g_RangeHigh > 0 ? g_RangeHigh : SymbolInfoDouble(_Symbol, SYMBOL_BID));
   ObjectSetString(0,  lblName, OBJPROP_TEXT, StringFormat("%02d:%02d", InpSessionHour, InpSessionMinute));
   ObjectSetInteger(0, lblName, OBJPROP_COLOR,      InpColorSession);
   ObjectSetInteger(0, lblName, OBJPROP_FONTSIZE,   9);
   ObjectSetInteger(0, lblName, OBJPROP_ANCHOR,     ANCHOR_LEFT_LOWER);
   ObjectSetInteger(0, lblName, OBJPROP_SELECTABLE, false);
}

//+------------------------------------------------------------------+
//| DrawRangeLevels — lineas High y Low del rango ORB               |
//+------------------------------------------------------------------+
void DrawRangeLevels()
{
   // High del rango — linea punteada naranja
   string nameH = g_ObjPrefix + "RangeHigh";
   if(ObjectFind(0, nameH) >= 0) ObjectDelete(0, nameH);
   ObjectCreate(0, nameH, OBJ_HLINE, 0, 0, g_RangeHigh);
   ObjectSetInteger(0, nameH, OBJPROP_COLOR,      InpColorRange);
   ObjectSetInteger(0, nameH, OBJPROP_WIDTH,      1);
   ObjectSetInteger(0, nameH, OBJPROP_STYLE,      STYLE_DASHDOT);
   ObjectSetInteger(0, nameH, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, nameH, OBJPROP_HIDDEN,     true);

   string lblH = g_ObjPrefix + "RangeHighLbl";
   if(ObjectFind(0, lblH) >= 0) ObjectDelete(0, lblH);
   ObjectCreate(0, lblH, OBJ_TEXT, 0, g_RangeEndTime + PeriodSeconds(_Period), g_RangeHigh);
   ObjectSetString(0,  lblH, OBJPROP_TEXT, " H.Rango " + DoubleToString(g_RangeHigh, _Digits));
   ObjectSetInteger(0, lblH, OBJPROP_COLOR,      InpColorRange);
   ObjectSetInteger(0, lblH, OBJPROP_FONTSIZE,   9);
   ObjectSetInteger(0, lblH, OBJPROP_ANCHOR,     ANCHOR_LEFT);
   ObjectSetInteger(0, lblH, OBJPROP_SELECTABLE, false);

   // Low del rango
   string nameL = g_ObjPrefix + "RangeLow";
   if(ObjectFind(0, nameL) >= 0) ObjectDelete(0, nameL);
   ObjectCreate(0, nameL, OBJ_HLINE, 0, 0, g_RangeLow);
   ObjectSetInteger(0, nameL, OBJPROP_COLOR,      InpColorRange);
   ObjectSetInteger(0, nameL, OBJPROP_WIDTH,      1);
   ObjectSetInteger(0, nameL, OBJPROP_STYLE,      STYLE_DASHDOT);
   ObjectSetInteger(0, nameL, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, nameL, OBJPROP_HIDDEN,     true);

   string lblL = g_ObjPrefix + "RangeLowLbl";
   if(ObjectFind(0, lblL) >= 0) ObjectDelete(0, lblL);
   ObjectCreate(0, lblL, OBJ_TEXT, 0, g_RangeEndTime + PeriodSeconds(_Period), g_RangeLow);
   ObjectSetString(0,  lblL, OBJPROP_TEXT, " L.Rango " + DoubleToString(g_RangeLow, _Digits));
   ObjectSetInteger(0, lblL, OBJPROP_COLOR,      InpColorRange);
   ObjectSetInteger(0, lblL, OBJPROP_FONTSIZE,   9);
   ObjectSetInteger(0, lblL, OBJPROP_ANCHOR,     ANCHOR_LEFT);
   ObjectSetInteger(0, lblL, OBJPROP_SELECTABLE, false);
}

//+------------------------------------------------------------------+
//| ColorRangeCandles — pinta velas del rango en naranja            |
//+------------------------------------------------------------------+
void ColorRangeCandles()
{
   int total = iBars(_Symbol, _Period);
   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);
      if(t >= g_RangeEndTime)  continue;
      if(t < g_RangeStartTime) break;

      string name = g_ObjPrefix + "Candle_" + TimeToString(t, TIME_DATE|TIME_MINUTES);
      if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);

      double o = iOpen (_Symbol, _Period, i);
      double h = iHigh (_Symbol, _Period, i);
      double l = iLow  (_Symbol, _Period, i);
      double c = iClose(_Symbol, _Period, i);

      // Cuerpo de la vela como rectangulo
      ObjectCreate(0, name, OBJ_RECTANGLE, 0,
                   t, MathMax(o, c),
                   t + PeriodSeconds(_Period) - 1, MathMin(o, c));
      ObjectSetInteger(0, name, OBJPROP_COLOR,     InpColorRange);
      ObjectSetInteger(0, name, OBJPROP_BGCOLOR,   InpColorRange);
      ObjectSetInteger(0, name, OBJPROP_FILL,      true);
      ObjectSetInteger(0, name, OBJPROP_WIDTH,     1);
      ObjectSetInteger(0, name, OBJPROP_SELECTABLE,false);
      ObjectSetInteger(0, name, OBJPROP_HIDDEN,    true);
   }
   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DrawTradeLevels — dibuja TP, SL (y BE si aplica) al activarse  |
//+------------------------------------------------------------------+
void DrawTradeLevels(ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;

   double sl = PositionGetDouble(POSITION_SL);
   double tp = PositionGetDouble(POSITION_TP);

   // TP — verde
   CreateHLine(g_ObjPrefix + "TP", tp, InpColorTP, 2, STYLE_SOLID, "TP");

   // SL — rojo
   CreateHLine(g_ObjPrefix + "SL", sl, InpColorSL, 2, STYLE_SOLID, "SL");

   // BE — cian (solo si esta configurado y aun no fue aplicado)
   if(InpBE_Pips > 0.0 && !g_BEApplied)
   {
      double openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
      double beTrigger = 0.0;
      ENUM_POSITION_TYPE posType = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
      if(posType == POSITION_TYPE_BUY)
         beTrigger = NormalizeDouble(openPrice + InpBE_Pips * g_PipSize, _Digits);
      else
         beTrigger = NormalizeDouble(openPrice - InpBE_Pips * g_PipSize, _Digits);

      CreateHLine(g_ObjPrefix + "BE_Trigger", beTrigger, InpColorBE, 1, STYLE_DASH, "BE Trigger");
   }

   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DrawBELine — dibuja linea BE en precio de entrada al aplicarse  |
//+------------------------------------------------------------------+
void DrawBELine(double price)
{
   // Eliminar linea de trigger
   string trigName = g_ObjPrefix + "BE_Trigger";
   if(ObjectFind(0, trigName) >= 0) ObjectDelete(0, trigName);
   string trigLbl = trigName + "_lbl";
   if(ObjectFind(0, trigLbl) >= 0) ObjectDelete(0, trigLbl);

   // Dibujar BE aplicado en precio de entrada
   CreateHLine(g_ObjPrefix + "BE_Applied", price, InpColorBE, 2, STYLE_DASH, "BE");
   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DeleteTradeLines — elimina lineas de TP/SL/BE del grafico       |
//+------------------------------------------------------------------+
void DeleteTradeLines()
{
   string names[] = {"TP", "SL", "BE_Trigger", "BE_Applied"};
   for(int i = 0; i < ArraySize(names); i++)
   {
      string n = g_ObjPrefix + names[i];
      if(ObjectFind(0, n) >= 0) ObjectDelete(0, n);
      string nl = n + "_lbl";
      if(ObjectFind(0, nl) >= 0) ObjectDelete(0, nl);
   }
   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DeleteDayObjects — elimina objetos del dia anterior             |
//+------------------------------------------------------------------+
void DeleteDayObjects()
{
   // Eliminar todos los objetos con el prefijo del EA
   int total = ObjectsTotal(0);
   for(int i = total - 1; i >= 0; i--)
   {
      string name = ObjectName(0, i);
      if(StringFind(name, g_ObjPrefix) == 0)
      {
         // Conservar panel (lo recrea DrawPanelInfo)
         if(StringFind(name, "Panel") >= 0 || StringFind(name, "Edge") >= 0) continue;
         ObjectDelete(0, name);
      }
   }
   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DeleteAllObjects — limpieza total al cerrar el EA               |
//+------------------------------------------------------------------+
void DeleteAllObjects()
{
   int total = ObjectsTotal(0);
   for(int i = total - 1; i >= 0; i--)
   {
      string name = ObjectName(0, i);
      if(StringFind(name, g_ObjPrefix) == 0)
         ObjectDelete(0, name);
   }
   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DrawPanelInfo — panel izquierdo con informacion del EA          |
//+------------------------------------------------------------------+
void DrawPanelInfo(string status)
{
   double balance  = AccountInfoDouble(ACCOUNT_BALANCE);
   double equity   = AccountInfoDouble(ACCOUNT_EQUITY);
   string riskStr  = InpUsePercentRisk
                     ? StringFormat("%.1f%% = $%.2f", InpRiskPercent, balance * InpRiskPercent / 100.0)
                     : StringFormat("$%.2f fijo", InpRiskUSD);
   string timeStr  = TimeToString(TimeCurrent(), TIME_DATE|TIME_MINUTES);
   string dateStr  = TimeToString(TimeCurrent(), TIME_DATE);
   string hourStr  = TimeToString(TimeCurrent(), TIME_MINUTES);

   // Rectangulo de fondo del panel
   string bgName = g_ObjPrefix + "PanelBG";
   if(ObjectFind(0, bgName) < 0)
   {
      ObjectCreate(0, bgName, OBJ_RECTANGLE_LABEL, 0, 0, 0);
      ObjectSetInteger(0, bgName, OBJPROP_CORNER,    CORNER_LEFT_UPPER);
      ObjectSetInteger(0, bgName, OBJPROP_XDISTANCE, 10);
      ObjectSetInteger(0, bgName, OBJPROP_YDISTANCE, 30);
      ObjectSetInteger(0, bgName, OBJPROP_XSIZE,     210);
      ObjectSetInteger(0, bgName, OBJPROP_YSIZE,     240);
      ObjectSetInteger(0, bgName, OBJPROP_BGCOLOR,   C'15,15,25');
      ObjectSetInteger(0, bgName, OBJPROP_BORDER_COLOR, C'50,80,120');
      ObjectSetInteger(0, bgName, OBJPROP_BORDER_TYPE, BORDER_FLAT);
      ObjectSetInteger(0, bgName, OBJPROP_WIDTH,     1);
      ObjectSetInteger(0, bgName, OBJPROP_BACK,      false);
      ObjectSetInteger(0, bgName, OBJPROP_SELECTABLE,false);
   }

   // Titulo del panel
   DrawLabel(g_ObjPrefix + "P_Title",   "  ORB EA v2.0 | XAUUSD",   14, 36,  clrGold,      10, true);
   DrawLabel(g_ObjPrefix + "P_Div1",    "─────────────────────────", 14, 50,  C'60,80,100',  8, false);

   // Informacion
   DrawLabel(g_ObjPrefix + "P_Time",    "  Hora  : " + hourStr,      14, 62,  clrWhite,      9, false);
   DrawLabel(g_ObjPrefix + "P_Date",    "  Fecha : " + dateStr,      14, 76,  clrWhite,      9, false);
   DrawLabel(g_ObjPrefix + "P_Symbol",  "  Activo: " + _Symbol,      14, 90,  clrWhite,      9, false);

   DrawLabel(g_ObjPrefix + "P_Div2",    "─────────────────────────", 14, 104, C'60,80,100',  8, false);

   DrawLabel(g_ObjPrefix + "P_Risk",    "  Riesgo: " + riskStr,      14, 116, clrYellow,     9, false);
   DrawLabel(g_ObjPrefix + "P_Bal",     StringFormat("  Balance: $%.2f", balance), 14, 130, clrLightGreen, 9, false);
   DrawLabel(g_ObjPrefix + "P_Eq",      StringFormat("  Equity : $%.2f", equity),  14, 144, clrLightGreen, 9, false);

   DrawLabel(g_ObjPrefix + "P_Div3",    "─────────────────────────", 14, 158, C'60,80,100',  8, false);

   // Estado y direccion
   color statusColor = (status == "EN POSICION") ? clrCyan
                     : (status == "COMPLETADO")  ? clrLimeGreen
                     : (StringFind(status, "RUPTURA") >= 0) ? clrYellow
                     : clrWhite;
   DrawLabel(g_ObjPrefix + "P_Status",  "  Estado: " + status,       14, 170, statusColor,   9, false);
   DrawLabel(g_ObjPrefix + "P_Dir",     "  Direc : " + GetDirectionStr(), 14, 184, clrOrange, 9, false);

   DrawLabel(g_ObjPrefix + "P_Div4",    "─────────────────────────", 14, 198, C'60,80,100',  8, false);
   DrawLabel(g_ObjPrefix + "P_EA",      "  ORB Breakout Strategy",   14, 210, C'80,100,140',  8, false);
   DrawLabel(g_ObjPrefix + "P_Ver",     "  Jose's Trading Suite",    14, 222, C'80,100,140',  8, false);

   // Frase de edge psicologico (esquina inferior izquierda del grafico)
   DrawEdgeLabel();

   ChartRedraw(0);
}

//+------------------------------------------------------------------+
//| DrawLabel — helper para etiquetas del panel                     |
//+------------------------------------------------------------------+
void DrawLabel(string name, string text, int x, int y, color clr, int fontSize, bool bold)
{
