   696	
   697	   double sl = PositionGetDouble(POSITION_SL);
   698	   double tp = PositionGetDouble(POSITION_TP);
   699	
   700	   // TP — verde
   701	   CreateHLine(g_ObjPrefix + "TP", tp, InpColorTP, 2, STYLE_SOLID, "TP");
   702	
   703	   // SL — rojo
   704	   CreateHLine(g_ObjPrefix + "SL", sl, InpColorSL, 2, STYLE_SOLID, "SL");
   705	
   706	   // BE — cian (solo si esta configurado y aun no fue aplicado)
   707	   if(InpBE_Pips > 0.0 && !g_BEApplied)
   708	   {
   709	      double openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
   710	      double beTrigger = 0.0;
   711	      ENUM_POSITION_TYPE posType = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   712	      if(posType == POSITION_TYPE_BUY)
   713	         beTrigger = NormalizeDouble(openPrice + InpBE_Pips * g_PipSize, _Digits);
   714	      else
   715	         beTrigger = NormalizeDouble(openPrice - InpBE_Pips * g_PipSize, _Digits);
   716	
   717	      CreateHLine(g_ObjPrefix + "BE_Trigger", beTrigger, InpColorBE, 1, STYLE_DASH, "BE Trigger");
   718	   }
   719	
   720	   ChartRedraw(0);
   721	}
