//+------------------------------------------------------------------+
//| CreateHLine — crea linea horizontal en el grafico               |
//+------------------------------------------------------------------+
void CreateHLine(string name, double price, color clr, int width, ENUM_LINE_STYLE style, string labelText)
{
   if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);

   ObjectCreate(0, name, OBJ_HLINE, 0, 0, price);
   ObjectSetInteger(0, name, OBJPROP_COLOR,    clr);
   ObjectSetInteger(0, name, OBJPROP_WIDTH,    width);
   ObjectSetInteger(0, name, OBJPROP_STYLE,    style);
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_HIDDEN,   true);

   // Etiqueta de precio al lado derecho
   string lblName = name + "_lbl";
   if(ObjectFind(0, lblName) >= 0) ObjectDelete(0, lblName);
   ObjectCreate(0, lblName, OBJ_TEXT, 0, TimeCurrent() + PeriodSeconds(_Period) * 3, price);
   ObjectSetString(0,  lblName, OBJPROP_TEXT, " " + labelText + " " + DoubleToString(price, _Digits));
   ObjectSetInteger(0, lblName, OBJPROP_COLOR,    clr);
   ObjectSetInteger(0, lblName, OBJPROP_FONTSIZE, 9);
   ObjectSetInteger(0, lblName, OBJPROP_ANCHOR,   ANCHOR_LEFT);
   ObjectSetInteger(0, lblName, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, lblName, OBJPROP_HIDDEN,   true);
}

