    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [new Paragraph({ children: [new TextRun({ text: txt, bold: !!bold, size: 19, font: "Arial", color: clr || "000000" })] })]
  });
  const mkCell2 = (txt, bg, bold, clr) => new TableCell({
    borders, width: { size: colW[1], type: WidthType.DXA },
    shading: { fill: bg || WHITE, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [new Paragraph({ children: [new TextRun({ text: txt, bold: !!bold, size: 19, font: "Arial", color: clr || "000000" })] })]
  });

  const tableRows = [];
  if (hdr) {
    tableRows.push(new TableRow({ tableHeader: true, children: [
      new TableCell({ borders, width: { size: colW[0], type: WidthType.DXA }, shading: { fill: BLUE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: hdr[0], bold: true, size: 20, font: "Arial", color: WHITE })] })] }),
      new TableCell({ borders, width: { size: colW[1], type: WidthType.DXA }, shading: { fill: BLUE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: hdr[1], bold: true, size: 20, font: "Arial", color: WHITE })] })] }),
    ]}));
  }
  rows.forEach(([c1, c2, bg1, bg2, b1, b2, clr1, clr2]) => {
    tableRows.push(new TableRow({ children: [mkCell(c1, bg1, b1, clr1), mkCell2(c2, bg2, b2, clr2)] }));
  });
  return new Table({ width: { size: W, type: WidthType.DXA }, columnWidths: colW, rows: tableRows });
}

// 3-col table
function tbl3(rows, colW = [2400, 3480, 3480], hdr = null) {
  const mkC = (txt, bg, bold, clr, w) => new TableCell({
    borders, width: { size: w, type: WidthType.DXA },
