{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageBreak
} = require('docx');
const fs = require('fs');

// ─── Colores ────────────────────────────────────────────────────────
const BLUE       = "1F4E79";
const BLUE_MID   = "2E75B6";
const BLUE_LIGHT = "D6E4F0";
const BLUE_HDR   = "BDD7EE";
const GREEN_BG   = "E2EFDA";
const GREEN_TXT  = "375623";
const RED_BG     = "FCE4D6";
const RED_TXT    = "833C00";
const AMBER_BG   = "FFF2CC";
const AMBER_TXT  = "7F6000";
const INFO_BG    = "DEEAF1";
const INFO_TXT   = "1F4E79";
const GRAY_BG    = "F2F2F2";
const CYAN_BG    = "E0F7F7";
const CYAN_TXT   = "006666";
const ORANGE_BG  = "FDE9D9";
const ORANGE_TXT = "974706";
const PURPLE_BG  = "EDE7F6";
const PURPLE_TXT = "4527A0";
const WHITE      = "FFFFFF";
const DARK_BG    = "1A1A2E";

const W = 9360; // content width US Letter 1" margins

// ─── Borders ────────────────────────────────────────────────────────
const b1 = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: b1, bottom: b1, left: b1, right: b1 };
const nb = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: nb, bottom: nb, left: nb, right: nb };

// ─── Helpers ────────────────────────────────────────────────────────
const sp = (sz = 120) => new Paragraph({ spacing: { before: sz, after: 0 }, children: [new TextRun("")] });

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 320, after: 160 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: BLUE_MID, space: 1 } },
    children: [new TextRun({ text, bold: true, size: 28, color: BLUE, font: "Arial" })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 220, after: 100 },
    children: [new TextRun({ text, bold: true, size: 24, color: BLUE_MID, font: "Arial" })]
  });
}

function h3(text) {
  return new Paragraph({
    spacing: { before: 160, after: 80 },
    children: [new TextRun({ text, bold: true, size: 21, color: "2E4057", font: "Arial" })]
  });
}

function p(text, opts = {}) {
  return new Paragraph({
    spacing: { before: 60, after: 80 },
    children: [new TextRun({ text, size: 20, font: "Arial", ...opts })]
  });
}

function pRuns(runs) {
  return new Paragraph({
    spacing: { before: 60, after: 80 },
    children: runs.map(r => new TextRun({ size: 20, font: "Arial", ...r }))
  });
}

function mono(text) {
  return new TextRun({ text, font: "Courier New", size: 18, color: "1A237E" });
}

function bullet(text, opts = {}) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, size: 20, font: "Arial", ...opts })]
  });
}

function numbered(text, opts = {}) {
  return new Paragraph({
    numbering: { reference: "numbers", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, size: 20, font: "Arial", ...opts })]
  });
}

// Callout box (single-col table)
function callout(title, body, bg, titleColor) {
  return new Table({
    width: { size: W, type: WidthType.DXA }, columnWidths: [W],
    rows: [new TableRow({ children: [new TableCell({
      borders, shading: { fill: bg, type: ShadingType.CLEAR },
      margins: { top: 100, bottom: 100, left: 200, right: 200 },
      width: { size: W, type: WidthType.DXA },
      children: [
        new Paragraph({ spacing: { after: 60 }, children: [new TextRun({ text: title, bold: true, size: 20, font: "Arial", color: titleColor })] }),
        new Paragraph({ spacing: { before: 0 }, children: [new TextRun({ text: body, size: 19, font: "Arial", color: "333333" })] }),
      ]
    })})]
  });
}

// Code block (dark background)
function codeBlock(lines) {
  const children = lines.map(line =>
    new Paragraph({ spacing: { before: 0, after: 0 }, children: [mono(line)] })
  );
  return new Table({
    width: { size: W, type: WidthType.DXA }, columnWidths: [W],
    rows: [new TableRow({ children: [new TableCell({
      borders, shading: { fill: "1A1A2E", type: ShadingType.CLEAR },
      margins: { top: 100, bottom: 100, left: 200, right: 200 },
      width: { size: W, type: WidthType.DXA },
      children
    })})]
  });
}

// 2-col table
function tbl2(rows, colW = [3000, 6360], hdr = null) {
