        ["ORB_v2_XAU_RangeLow",       "Línea horizontal Low del rango",               GRAY_BG, WHITE, true],
        ["ORB_v2_XAU_RangeLowLbl",    "Etiqueta \" L.Rango XXXX.XX\"",               GRAY_BG, WHITE],
        ["ORB_v2_XAU_Candle_YYYY.MM.DD HH:MM", "Rectángulo naranja sobre vela del rango", GRAY_BG, WHITE, true],
        ["ORB_v2_XAU_TP",             "Línea TP verde sólida",                       GREEN_BG, WHITE, true, false, GREEN_TXT],
        ["ORB_v2_XAU_TP_lbl",         "Etiqueta \" TP XXXX.XX\" verde",              GREEN_BG, WHITE],
        ["ORB_v2_XAU_SL",             "Línea SL roja sólida",                        RED_BG,   WHITE, true, false, RED_TXT],
        ["ORB_v2_XAU_SL_lbl",         "Etiqueta \" SL XXXX.XX\" roja",              RED_BG,   WHITE],
        ["ORB_v2_XAU_BE_Trigger",     "Línea nivel activación BE (cian dash)",        CYAN_BG,  WHITE, true, false, CYAN_TXT],
        ["ORB_v2_XAU_BE_Trigger_lbl", "Etiqueta \" BE Trigger XXXX.XX\"",            CYAN_BG,  WHITE],
        ["ORB_v2_XAU_BE_Applied",     "Línea BE aplicado en precio de entrada",       CYAN_BG,  WHITE, true, false, CYAN_TXT],
        ["ORB_v2_XAU_BE_Applied_lbl", "Etiqueta \" BE XXXX.XX\"",                    CYAN_BG,  WHITE],
        ["ORB_v2_XAU_PanelBG",        "Rectángulo de fondo del panel",               PURPLE_BG,WHITE, true, false, PURPLE_TXT],
        ["ORB_v2_XAU_P_Title/Time/etc","Etiquetas del panel (11 labels en total)",    PURPLE_BG,WHITE],
        ["ORB_v2_XAU_EdgePhrase",      "Frase de edge psicológico permanente",        AMBER_BG, WHITE, true, false, AMBER_TXT],
      ], [3400, 5960], ["Nombre del objeto", "Descripción"]),
      sp(),

      // ── 7. RESULTADOS VALIDADOS ───────────────────────────────────
      h1("7. Resultados validados — configuración óptima"),
      h2("7.1 Configuración ganadora (Set 2 + filtro Lun+Vie + $25/trade)"),
      callout(
        "Esta es la única configuración que pasa el límite del 5% DD de FundingPips en IS y OOS simultáneamente",
        "IS DD: 3.36% ($168) | OOS DD: 4.64% ($232) | Límite FundingPips: 5.0% ($250). Margen de seguridad OOS: $18. La v1.2 con filtro H4 aumentará ese margen eliminando Viernes SELL.",
        GREEN_BG, GREEN_TXT
      ),
      sp(80),
      tbl3([
        [{ text: "Métrica",             bold: true }, { text: "IS — Backtest", bold: true }, { text: "OOS — Forward", bold: true }],
        ["Período",           "Ene 2024 → Ene 2025",   "Feb 2025 → Feb 2026"],
        ["Trades totales",    "76",                     "90"],
        ["Win Rate",          "39.5%",                  "38.9%"],
        ["Profit Factor",     "1.413",                  "1.379"],
        ["Net Profit",        "+$456 (escalado $25)",   "+$500 (escalado $25)"],
        ["Max DD balance",    { text: "3.36% — $168", bg: GREEN_BG, clr: GREEN_TXT }, { text: "4.64% — $232", bg: GREEN_BG, clr: GREEN_TXT }],
        ["Racha pérd. máx.",  "7 consecutivas",         "9 consecutivas"],
        ["Meses positivos",   "9/13 (69%)",             "12/14 (86%)"],
        ["Sesión",            "17:00 NY open",          "17:00 NY open"],
        ["Días activos",      "Lunes + Viernes",        "Lunes + Viernes"],
      ], [2800, 3280, 3280]),
      sp(100),

      h2("7.2 Análisis de segmentos día × dirección (OOS/Forward)"),
      tbl3([
        [{ text: "Segmento",    bold: true }, { text: "PF", bold: true }, { text: "Net OOS", bold: true }],
        ["Lunes BUY",   { text: "2.571 ★★", bg: GREEN_BG, clr: GREEN_TXT }, { text: "+$539", bg: GREEN_BG, clr: GREEN_TXT }],
        ["Viernes BUY", { text: "1.500",    bg: GREEN_BG, clr: GREEN_TXT }, { text: "+$294", bg: GREEN_BG, clr: GREEN_TXT }],
        ["Viernes SELL",{ text: "1.592",    bg: GREEN_BG, clr: GREEN_TXT }, { text: "+$203", bg: GREEN_BG, clr: GREEN_TXT }],
        ["Lunes SELL",  { text: "0.643 ✗",  bg: RED_BG,   clr: RED_TXT   }, { text: "-$210", bg: RED_BG,   clr: RED_TXT   }],
      ], [2800, 3280, 3280], ["Segmento", "PF OOS", "Net OOS"]),
      sp(80),
      callout(
        "Pendiente v1.2: Lunes SELL es el único segmento negativo consistente en IS y OOS",
        "IS: PF 1.12 (+$77) → OOS: PF 0.64 (-$210). El filtro H4 MA(50) bloqueará SELL cuando precio > MA en H4, eliminando este segmento automáticamente. Proyección: DD OOS bajaría de 4.64% a ~3.5%.",
        AMBER_BG, AMBER_TXT
      ),
      sp(),

      // ── 8. PLAN DE VERSIONES ──────────────────────────────────────
      h1("8. Plan de versiones — roadmap"),
      tbl3([
        [{ text: "v1.1", bg: GREEN_BG, bold: true },    { text: "COMPLETADA", bg: GREEN_BG, clr: GREEN_TXT }, "InpTradeDirection ENUM (DIR_BOTH/BUY_ONLY/SELL_ONLY). Sin cambios en lógica de trading."],
        [{ text: "v2.0", bg: GREEN_BG, bold: true },    { text: "COMPLETADA", bg: GREEN_BG, clr: GREEN_TXT }, "Sistema visual completo (9 indicaciones). Panel OBJ. Parámetros validados Lun+Vie+$25."],
        [{ text: "v2.0 WTI", bg: GREEN_BG, bold: true },{ text: "COMPLETADA", bg: GREEN_BG, clr: GREEN_TXT }, "Versión paralela para USOIL. Magic=20260402. TP=100/SL=50. Frase: \"El petróleo no te paga por opinar\""],
        [{ text: "v1.2", bg: AMBER_BG, bold: true },    { text: "PENDIENTE",  bg: AMBER_BG, clr: AMBER_TXT }, "Filtro H4 MA(50): bloquear SELL cuando precio > MA H4 (especialmente Lunes). Proyección: DD ~3.5%."],
        [{ text: "v2.1 Forex", bg: INFO_BG, bold: true },{ text: "PENDIENTE",  bg: INFO_BG, clr: INFO_TXT  }, "4 versiones: EURUSD, GBPUSD, USDJPY, EURJPY. SessionHour diferente por par. Grids 216-300 combos."],
