     1	//+------------------------------------------------------------------+
     2	//|                                    ORB_BreakoutEA_v2_XAUUSD.mq5 |
     3	//|                   Opening Range Breakout Expert Advisor v2.00    |
     4	//|                             Jose's Trading Suite - Abril 2026    |
     5	//+------------------------------------------------------------------+
     6	//|  DESCRIPCION:                                                    |
     7	//|  EA ORB consolidado para XAUUSD con visualizacion completa:      |
     8	//|   - Linea vertical punteada blanca en inicio de sesion           |
     9	//|   - Lineas TP (verde), SL (rojo), BE (cian) con precios         |
    10	//|   - Solo visible al activarse la posicion                        |
    11	//|   - Rango ORB marcado (High/Low) con velas naranjas             |
    12	//|   - Panel izquierdo con info completa del EA                     |
    13	//|   - Frase de edge psicologico en el grafico                     |
    14	//|                                                                  |
    15	//|  CAMBIOS v2.0 vs v1.1:                                          |
    16	//|   + InpTradeDirection (DIR_BOTH/BUY_ONLY/SELL_ONLY)             |
    17	//|   + Sistema visual completo con objetos en el grafico           |
    18	//|   + Panel informativo de objetos (no Comment)                   |
    19	//+------------------------------------------------------------------+
    20	#property copyright   "Jose's Trading Suite"
    21	#property link        ""
    22	#property version     "2.00"
    23	#property description "ORB EA v2 XAUUSD - Con visualizacion completa"
    24	
    25	#include <Trade\Trade.mqh>
    26	
    27	//+------------------------------------------------------------------+
    28	//|  ENUM DE DIRECCION                                               |
    29	//+------------------------------------------------------------------+
    30	enum ENUM_ORB_DIRECTION
    31	{
    32	   DIR_BOTH      = 0,  // Ambos — BUY STOP + SELL STOP
    33	   DIR_BUY_ONLY  = 1,  // Solo compras — BUY STOP en el High
    34	   DIR_SELL_ONLY = 2   // Solo ventas  — SELL STOP en el Low
    35	};
    36	
    37	//+------------------------------------------------------------------+
    38	//|  PARAMETROS DE ENTRADA                                           |
    39	//+------------------------------------------------------------------+
    40	
    41	input group "=== CONFIGURACION DEL RANGO ORB ==="
    42	input int     InpRangeCandles    = 4;            // Numero de velas del rango inicial
    43	input int     InpSessionHour     = 17;           // Hora inicio sesion (hora servidor GMT)
    44	input int     InpSessionMinute   = 0;            // Minutos inicio sesion
    45	
    46	input group "=== GESTION DE RIESGO ==="
    47	input double  InpTP_Pips         = 130.0;        // Take Profit (pips)
    48	input double  InpSL_Pips         = 60.0;         // Stop Loss (pips)
    49	input double  InpBE_Pips         = 0.0;          // Breakeven trigger (pips, 0 = desactivado)
    50	input double  InpRiskUSD         = 25.0;         // Riesgo en USD por operacion
    51	input bool    InpUsePercentRisk  = false;         // Usar % del balance en lugar de USD
    52	input double  InpRiskPercent     = 1.0;          // Riesgo en % si UsePercentRisk = true
    53	
    54	input group "=== DIAS PERMITIDOS ==="
    55	input bool    InpAllowMonday     = true;          // Lunes
    56	input bool    InpAllowTuesday    = false;         // Martes
    57	input bool    InpAllowWednesday  = false;         // Miercoles
    58	input bool    InpAllowThursday   = false;         // Jueves
    59	input bool    InpAllowFriday     = true;          // Viernes
    60	input bool    InpAllowSaturday   = false;         // Sabado
    61	input bool    InpAllowSunday     = false;         // Domingo
    62	
    63	input group "=== CONFIGURACION GENERAL ==="
