   232	//+------------------------------------------------------------------+
   233	//| BuildRange                                                       |
   234	//+------------------------------------------------------------------+
   235	bool BuildRange()
   236	{
   237	   double  hi    = 0.0;
   238	   double  lo    = DBL_MAX;
   239	   int     count = 0;
   240	   int     total = iBars(_Symbol, _Period);
   241	
   242	   for(int i = 1; i < total; i++)
   243	   {
   244	      datetime t = iTime(_Symbol, _Period, i);
   245	      if(t >= g_RangeEndTime)  continue;
   246	      if(t < g_RangeStartTime) break;
   247	      double barHi = iHigh(_Symbol, _Period, i);
   248	      double barLo = iLow (_Symbol, _Period, i);
   249	      if(barHi > hi) hi = barHi;
   250	      if(barLo < lo) lo = barLo;
   251	      count++;
   252	   }
   253	
   254	   PrintFormat("BuildRange: %d vela(s) en [%s - %s]", count,
   255	               TimeToString(g_RangeStartTime, TIME_MINUTES),
   256	               TimeToString(g_RangeEndTime,   TIME_MINUTES));
   257	
   258	   if(count == 0 || hi <= lo || hi == 0.0) return false;
   259	
   260	   g_RangeHigh = hi;
   261	   g_RangeLow  = lo;
   262	   return true;
   263	}
