   266	//| PlacePendingOrders — con filtro InpTradeDirection               |
   267	//+------------------------------------------------------------------+
   268	void PlacePendingOrders()
   269	{
   270	   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   271	   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   272	   double slDist  = InpSL_Pips * g_PipSize;
   273	   double tpDist  = InpTP_Pips * g_PipSize;
   274	   double minDist = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   275	   double lots    = CalculateLotSize();
   276	   bool   placed  = false;
   277	
   278	   if(lots <= 0.0)
   279	   {
   280	      Print("PlacePendingOrders: lotaje invalido. Saltando dia.");
   281	      g_TradeDone = true;
   282	      return;
   283	   }
   284	
   285	   // BUY STOP
   286	   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY)
   287	   {
   288	      if(g_RangeHigh > ask + minDist)
   289	      {
   290	         double entry = NormalizeDouble(g_RangeHigh, _Digits);
   291	         double sl    = NormalizeDouble(entry - slDist, _Digits);
   292	         double tp    = NormalizeDouble(entry + tpDist, _Digits);
   293	
   294	         if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
   295	         {
   296	            g_TicketBuy = g_Trade.ResultOrder();
   297	            Print("BUY STOP #", (string)g_TicketBuy, " E=", DoubleToString(entry, _Digits));
   298	            placed = true;
   299	         }
   300	         else PrintFormat("Error BUY STOP: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   301	      }
   302	      else PrintFormat("BUY STOP omitido: precio cerca del High");
   303	   }
   304	
   305	   // SELL STOP
   306	   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY)
   307	   {
   308	      if(g_RangeLow < bid - minDist)
   309	      {
   310	         double entry = NormalizeDouble(g_RangeLow, _Digits);
   311	         double sl    = NormalizeDouble(entry + slDist, _Digits);
   312	         double tp    = NormalizeDouble(entry - tpDist, _Digits);
   313	
   314	         if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
   315	         {
   316	            g_TicketSell = g_Trade.ResultOrder();
   317	            Print("SELL STOP #", (string)g_TicketSell, " E=", DoubleToString(entry, _Digits));
   318	            placed = true;
   319	         }
   320	         else PrintFormat("Error SELL STOP: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   321	      }
   322	      else PrintFormat("SELL STOP omitido: precio cerca del Low");
   323	   }
   324	
   325	   g_OrdersPlaced = placed;
   326	   if(!placed)
   327	   {
   328	      Print("Sin ordenes colocadas. Dia terminado.");
   329	      g_TradeDone = true;
   330	   }
   331	}
