   352	   }
   353	
   354	   if(g_OppCancelled)
   355	   {
   356	      if(InpOnlyOnePerDay)
   357	      {
   358	         g_TradeDone = true;
   359	         DeleteTradeLines();
   360	         Print("Posicion cerrada. Dia completado.");
   361	      }
