   383	//+------------------------------------------------------------------+
   384	//| ApplyBreakeven                                                   |
   385	//+------------------------------------------------------------------+
   386	void ApplyBreakeven(ulong ticket)
   387	{
   388	   if(!PositionSelectByTicket(ticket)) return;
   389	
   390	   ENUM_POSITION_TYPE posType    = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   391	   double             openPrice  = PositionGetDouble(POSITION_PRICE_OPEN);
   392	   double             currentSL  = PositionGetDouble(POSITION_SL);
   393	   double             currentTP  = PositionGetDouble(POSITION_TP);
   394	   double             beDistance = InpBE_Pips * g_PipSize;
   395	   double             bid        = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   396	   double             ask        = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   397	   double             newSL      = 0.0;
   398	   bool               doModify   = false;
   399	
   400	   if(posType == POSITION_TYPE_BUY)
   401	   {
   402	      if(bid >= openPrice + beDistance)
   403	      {
   404	         newSL = NormalizeDouble(openPrice, _Digits);
   405	         if(newSL > currentSL) doModify = true;
   406	      }
   407	   }
   408	   else
   409	   {
   410	      if(ask <= openPrice - beDistance)
   411	      {
   412	         newSL = NormalizeDouble(openPrice, _Digits);
   413	         if(currentSL == 0.0 || newSL < currentSL) doModify = true;
   414	      }
   415	   }
   416	
   417	   if(doModify)
   418	   {
   419	      if(g_Trade.PositionModify(ticket, newSL, currentTP))
   420	      {
   421	         g_BEApplied = true;
   422	         PrintFormat("BREAKEVEN aplicado | #%s  Nuevo SL=%.5f", (string)ticket, newSL);
   423	         if(InpShowVisuals) DrawBELine(newSL);
   424	      }
   425	      else PrintFormat("Error BE: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   426	   }
   427	}
