   429	//+------------------------------------------------------------------+
   430	//| CalculateLotSize                                                 |
   431	//+------------------------------------------------------------------+
   432	double CalculateLotSize()
   433	{
   434	   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   435	   double riskAmount = InpUsePercentRisk ? (balance * InpRiskPercent / 100.0) : InpRiskUSD;
   436	   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   437	   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   438	
   439	   if(tickSize <= 0.0 || tickValue <= 0.0) { PrintFormat("CalculateLotSize: tick info invalida"); return 0.0; }
   440	
   441	   double valuePerPip = tickValue * (g_PipSize / tickSize);
   442	   if(valuePerPip <= 0.0) return 0.0;
   443	
   444	   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   445	   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   446	   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   447	   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   448	
   449	   lots = MathFloor(lots / lotStep) * lotStep;
   450	   lots = MathMax(lots, minLot);
   451	   lots = MathMin(lots, maxLot);
   452	
   453	   PrintFormat("Lotaje: %.2f (Riesgo=$%.2f | Balance=$%.2f)", lots, riskAmount, balance);
   454	   return lots;
   455	}
