//| OnDeinit                                                         |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   CancelAllPendingOrders();
   DeleteAllObjects();
   Comment("");
   PrintFormat("ORB EA v2 XAU detenido. Razon: %d", reason);
