//+------------------------------------------------------------------+
//| OnTick                                                           |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime     now = TimeCurrent();
   MqlDateTime  dt;
   TimeToStruct(now, dt);

   if(dt.day != g_PrevDay)
   {
      ResetDay(now, dt.day_of_week);
      g_PrevDay = dt.day;
   }

   if(!IsDayAllowed(dt.day_of_week))
   {
      if(InpShowVisuals) DrawPanelInfo("DIA NO PERMITIDO");
      return;
   }

   if(g_TradeDone)
   {
      if(InpShowVisuals) DrawPanelInfo("COMPLETADO");
      return;
   }

   // FASE 1: Construir rango
   if(!g_RangeBuilt)
   {
      if(now < g_RangeEndTime)
      {
         if(InpShowVisuals) DrawPanelInfo("DEFINIENDO RANGO...");
         return;
      }
      if(BuildRange())
      {
         g_RangeBuilt = true;
         PrintFormat("RANGO DEFINIDO | H=%.5f  L=%.5f", g_RangeHigh, g_RangeLow);
         if(InpShowVisuals)
         {
            DrawSessionLine();
            DrawRangeLevels();
            ColorRangeCandles();
         }
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRange: sin velas validas. Saltando dia.");
         g_TradeDone = true;
         if(InpShowVisuals) DrawPanelInfo("SIN RANGO VALIDO");
      }
      return;
   }

   // FASE 2: Gestionar trade
   if(g_OrdersPlaced)
      ManageTrade();

   if(InpShowVisuals) DrawPanelInfo(GetStatusStr());
}

//+------------------------------------------------------------------+
//| ResetDay                                                         |
//+------------------------------------------------------------------+
void ResetDay(datetime now, int dayOfWeek)
{
   CancelAllPendingOrders();
   DeleteDayObjects();

   g_RangeHigh     = 0.0;
   g_RangeLow      = 0.0;
   g_RangeBuilt    = false;
   g_OrdersPlaced  = false;
   g_TradeDone     = false;
   g_BEApplied     = false;
   g_OppCancelled  = false;
   g_TicketBuy     = 0;
   g_TicketSell    = 0;

   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight + InpSessionHour * 3600 + InpSessionMinute * 60;
   g_RangeEndTime       = g_RangeStartTime + (long)InpRangeCandles * PeriodSeconds(_Period);

   if(IsDayAllowed(dayOfWeek))
      PrintFormat("Nuevo dia | Sesion: %s → Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
}

//+------------------------------------------------------------------+
//| BuildRange                                                       |
//+------------------------------------------------------------------+
bool BuildRange()
{
   double  hi    = 0.0;
   double  lo    = DBL_MAX;
   int     count = 0;
   int     total = iBars(_Symbol, _Period);

   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);
      if(t >= g_RangeEndTime)  continue;
      if(t < g_RangeStartTime) break;
      double barHi = iHigh(_Symbol, _Period, i);
      double barLo = iLow (_Symbol, _Period, i);
      if(barHi > hi) hi = barHi;
      if(barLo < lo) lo = barLo;
      count++;
   }

   PrintFormat("BuildRange: %d vela(s) en [%s - %s]", count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));

   if(count == 0 || hi <= lo || hi == 0.0) return false;

   g_RangeHigh = hi;
   g_RangeLow  = lo;
   return true;
}

//+------------------------------------------------------------------+
//| PlacePendingOrders — con filtro InpTradeDirection               |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist  = InpSL_Pips * g_PipSize;
   double tpDist  = InpTP_Pips * g_PipSize;
   double minDist = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots    = CalculateLotSize();
   bool   placed  = false;

   if(lots <= 0.0)
   {
      Print("PlacePendingOrders: lotaje invalido. Saltando dia.");
      g_TradeDone = true;
      return;
   }

   // BUY STOP
   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY)
   {
      if(g_RangeHigh > ask + minDist)
      {
         double entry = NormalizeDouble(g_RangeHigh, _Digits);
         double sl    = NormalizeDouble(entry - slDist, _Digits);
         double tp    = NormalizeDouble(entry + tpDist, _Digits);

         if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
         {
            g_TicketBuy = g_Trade.ResultOrder();
            Print("BUY STOP #", (string)g_TicketBuy, " E=", DoubleToString(entry, _Digits));
            placed = true;
         }
         else PrintFormat("Error BUY STOP: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
      else PrintFormat("BUY STOP omitido: precio cerca del High");
   }

   // SELL STOP
   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY)
   {
      if(g_RangeLow < bid - minDist)
      {
         double entry = NormalizeDouble(g_RangeLow, _Digits);
         double sl    = NormalizeDouble(entry + slDist, _Digits);
         double tp    = NormalizeDouble(entry - tpDist, _Digits);

         if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
         {
            g_TicketSell = g_Trade.ResultOrder();
            Print("SELL STOP #", (string)g_TicketSell, " E=", DoubleToString(entry, _Digits));
            placed = true;
         }
         else PrintFormat("Error SELL STOP: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
      else PrintFormat("SELL STOP omitido: precio cerca del Low");
   }

   g_OrdersPlaced = placed;
   if(!placed)
   {
      Print("Sin ordenes colocadas. Dia terminado.");
      g_TradeDone = true;
   }
}

//+------------------------------------------------------------------+
//| ManageTrade                                                      |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();

   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      {
         CancelAllPendingOrders();
         g_OppCancelled = true;
         Print("Breakout activado! Posicion #", (string)posTicket, " | Orden opuesta cancelada.");
         if(InpShowVisuals) DrawTradeLevels(posTicket);
      }
      if(!g_BEApplied && InpBE_Pips > 0.0)
         ApplyBreakeven(posTicket);
      return;
   }

   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay)
      {
         g_TradeDone = true;
         DeleteTradeLines();
         Print("Posicion cerrada. Dia completado.");
      }
      else
      {
         g_OppCancelled = false;
         g_BEApplied    = false;
         g_TicketBuy    = 0;
         g_TicketSell   = 0;
         DeleteTradeLines();
         PlacePendingOrders();
      }
      return;
   }

   bool buyPending  = (g_TicketBuy  > 0 && IsOrderPending(g_TicketBuy));
   bool sellPending = (g_TicketSell > 0 && IsOrderPending(g_TicketSell));
   if(!buyPending && !sellPending)
   {
      g_TradeDone = true;
      Print("Ordenes expiradas sin activacion. Dia terminado.");
   }
}

//+------------------------------------------------------------------+
//| ApplyBreakeven                                                   |
//+------------------------------------------------------------------+
void ApplyBreakeven(ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;

   ENUM_POSITION_TYPE posType    = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   double             openPrice  = PositionGetDouble(POSITION_PRICE_OPEN);
   double             currentSL  = PositionGetDouble(POSITION_SL);
   double             currentTP  = PositionGetDouble(POSITION_TP);
   double             beDistance = InpBE_Pips * g_PipSize;
   double             bid        = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double             ask        = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double             newSL      = 0.0;
   bool               doModify   = false;

   if(posType == POSITION_TYPE_BUY)
   {
      if(bid >= openPrice + beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(newSL > currentSL) doModify = true;
      }
   }
   else
   {
      if(ask <= openPrice - beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(currentSL == 0.0 || newSL < currentSL) doModify = true;
      }
   }

   if(doModify)
   {
      if(g_Trade.PositionModify(ticket, newSL, currentTP))
      {
         g_BEApplied = true;
         PrintFormat("BREAKEVEN aplicado | #%s  Nuevo SL=%.5f", (string)ticket, newSL);
         if(InpShowVisuals) DrawBELine(newSL);
      }
      else PrintFormat("Error BE: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   }
}

//+------------------------------------------------------------------+
//| CalculateLotSize                                                 |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk ? (balance * InpRiskPercent / 100.0) : InpRiskUSD;
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickValue <= 0.0) { PrintFormat("CalculateLotSize: tick info invalida"); return 0.0; }

   double valuePerPip = tickValue * (g_PipSize / tickSize);
   if(valuePerPip <= 0.0) return 0.0;

   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   PrintFormat("Lotaje: %.2f (Riesgo=$%.2f | Balance=$%.2f)", lots, riskAmount, balance);
   return lots;
}

//+------------------------------------------------------------------+
//| FindOpenPosition                                                 |
//+------------------------------------------------------------------+
ulong FindOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      ulong ticket = PositionGetTicket(i);
      if(PositionGetString(POSITION_SYMBOL) == _Symbol &&
         PositionGetInteger(POSITION_MAGIC) == (long)InpMagicNumber)
         return ticket;
   }
   return 0;
}

//+------------------------------------------------------------------+
//| IsOrderPending                                                   |
//+------------------------------------------------------------------+
bool IsOrderPending(ulong ticket)
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
      if(OrderGetTicket(i) == ticket) return true;
   return false;
}

//+------------------------------------------------------------------+
//| CancelAllPendingOrders                                           |
//+------------------------------------------------------------------+
void CancelAllPendingOrders()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      ulong ticket = OrderGetTicket(i);
      if(OrderGetInteger(ORDER_MAGIC) == (long)InpMagicNumber &&
         OrderGetString(ORDER_SYMBOL) == _Symbol)
      {
         if(g_Trade.OrderDelete(ticket)) Print("Orden cancelada: #", (string)ticket);
         else PrintFormat("Error cancelando #%s: %s (%d)", (string)ticket,
                          g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
   }
   g_TicketBuy  = 0;
   g_TicketSell = 0;
}

//+------------------------------------------------------------------+
//| IsDayAllowed                                                     |
//+------------------------------------------------------------------+
bool IsDayAllowed(int dow)
{
   switch(dow)
   {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
      default: return false;
   }
}

//+------------------------------------------------------------------+
//| DetectFillingType                                                |
//+------------------------------------------------------------------+
ENUM_ORDER_TYPE_FILLING DetectFillingType()
{
   uint filling = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((filling & SYMBOL_FILLING_FOK) != 0) return ORDER_FILLING_FOK;
   if((filling & SYMBOL_FILLING_IOC) != 0) return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
}

//+------------------------------------------------------------------+
//| GetStatusStr                                                     |
//+------------------------------------------------------------------+
string GetStatusStr()
{
   if(g_TradeDone)    return "COMPLETADO";
   if(g_OppCancelled) return "EN POSICION";
   if(g_OrdersPlaced) return "ESPERANDO RUPTURA";
   if(g_RangeBuilt)   return "RANGO DEFINIDO";
   return "DEFINIENDO RANGO";
}

//+------------------------------------------------------------------+
//| GetDirectionStr                                                  |
//+------------------------------------------------------------------+
string GetDirectionStr()
{
   switch(InpTradeDirection)
   {
      case DIR_BUY_ONLY:  return "SOLO COMPRAS";
      case DIR_SELL_ONLY: return "SOLO VENTAS";
      default:            return "AMBAS";
   }
}

