   659	void ColorRangeCandles()
   660	{
   661	   int total = iBars(_Symbol, _Period);
   662	   for(int i = 1; i < total; i++)
   663	   {
   664	      datetime t = iTime(_Symbol, _Period, i);
   665	      if(t >= g_RangeEndTime)  continue;
   666	      if(t < g_RangeStartTime) break;
   667	
   668	      string name = g_ObjPrefix + "Candle_" + TimeToString(t, TIME_DATE|TIME_MINUTES);
   669	      if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);
   670	
   671	      double o = iOpen (_Symbol, _Period, i);
   672	      double h = iHigh (_Symbol, _Period, i);
   673	      double l = iLow  (_Symbol, _Period, i);
   674	      double c = iClose(_Symbol, _Period, i);
   675	
   676	      // Cuerpo de la vela como rectangulo
   677	      ObjectCreate(0, name, OBJ_RECTANGLE, 0,
   678	                   t, MathMax(o, c),
   679	                   t + PeriodSeconds(_Period) - 1, MathMin(o, c));
   680	      ObjectSetInteger(0, name, OBJPROP_COLOR,     InpColorRange);
   681	      ObjectSetInteger(0, name, OBJPROP_BGCOLOR,   InpColorRange);
   682	      ObjectSetInteger(0, name, OBJPROP_FILL,      true);
