{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                         ORB_BreakoutEA_v3_SPMS_XAUUSD.mq5       |
//|              Opening Range Breakout EA v3.0 — Filtro SPMS        |
//|                    Jose's Trading Suite — Abril 2026             |
//+------------------------------------------------------------------+
//|  FILTRO SPMS: Session Pre-Momentum Slope                         |
//|  Calcula la pendiente de regresion lineal sobre los cierres de   |
//|  las N velas anteriores al rango ORB, normalizada por ATR(14).   |
//|  Score resultante va de -1.0 a +1.0:                             |
//|   > +InpSPMS_UmbralScore  => solo BUY STOP                       |
//|   < -InpSPMS_UmbralScore  => solo SELL STOP                      |
//|   entre -/+ umbral        => ambas ordenes (DIR_BOTH)            |
//|                                                                  |
//|  PARAMETROS NUEVOS vs v2.0:                                      |
//|   InpSPMS_Activo        — activa/desactiva el filtro             |
//|   InpSPMS_VelasLookback — velas M5 previas al rango (default 6)  |
//|   InpSPMS_PeriodoATR    — periodo del ATR normalizador (def. 14) |
//|   InpSPMS_UmbralScore   — umbral de activacion (default 0.30)    |
//+------------------------------------------------------------------+
#property copyright   "Jose's Trading Suite"
#property link        ""
#property version     "3.00"
#property description "ORB EA v3 SPMS XAUUSD — Filtro Session Pre-Momentum Slope"

#include <Trade\Trade.mqh>

//+------------------------------------------------------------------+
//|  ENUM DE DIRECCION                                               |
//+------------------------------------------------------------------+
enum ENUM_ORB_DIRECTION
{
   DIR_BOTH      = 0,  // Ambos — BUY STOP + SELL STOP
   DIR_BUY_ONLY  = 1,  // Solo compras — BUY STOP en el High
   DIR_SELL_ONLY = 2   // Solo ventas  — SELL STOP en el Low
};

//+------------------------------------------------------------------+
//|  PARAMETROS DE ENTRADA                                           |
//+------------------------------------------------------------------+

input group "=== CONFIGURACION DEL RANGO ORB ==="
input int    InpRangeCandles  = 4;     // Numero de velas del rango inicial
input int    InpSessionHour   = 17;    // Hora inicio sesion (hora servidor)
input int    InpSessionMinute = 0;     // Minutos inicio sesion

input group "=== GESTION DE RIESGO ==="
input double InpTP_Pips       = 130.0; // Take Profit en pips
input double InpSL_Pips       = 60.0;  // Stop Loss en pips
input double InpBE_Pips       = 0.0;   // Breakeven trigger en pips (0=desactivado)
input double InpRiskUSD       = 25.0;  // Riesgo en USD por operacion
input bool   InpUsePercentRisk = false; // true=usar % del balance, false=USD fijo
input double InpRiskPercent   = 1.0;   // Riesgo en % si InpUsePercentRisk=true

input group "=== DIAS PERMITIDOS ==="
input bool   InpAllowMonday    = true;  // Permitir operaciones el Lunes
input bool   InpAllowTuesday   = true;  // Permitir operaciones el Martes
input bool   InpAllowWednesday = true;  // Permitir operaciones el Miercoles
input bool   InpAllowThursday  = true;  // Permitir operaciones el Jueves
input bool   InpAllowFriday    = true;  // Permitir operaciones el Viernes
input bool   InpAllowSaturday  = false; // Permitir operaciones el Sabado
input bool   InpAllowSunday    = false; // Permitir operaciones el Domingo

input group "=== FILTRO SPMS — Session Pre-Momentum Slope ==="
input bool   InpSPMS_Activo        = true; // true=filtro activo, false=desactivado (solo InpTradeDirection)
input int    InpSPMS_VelasLookback = 6;    // Velas M5 previas al rango para calcular pendiente [4..12]
input int    InpSPMS_PeriodoATR    = 14;   // Periodo del ATR usado para normalizar la pendiente [7..21]
input double InpSPMS_UmbralScore   = 0.30; // Score minimo para forzar direccion. Zona neutra=[-umbral,+umbral] [0.10..0.60]

input group "=== CONFIGURACION GENERAL ==="
input ENUM_ORB_DIRECTION InpTradeDirection = DIR_BOTH; // Direccion base: Ambos/Solo Compras/Solo Ventas
input bool   InpOnlyOnePerDay = true;      // Solo un trade por dia
input int    InpMagicNumber   = 20260501;  // Magic Number unico del EA
input string InpComment       = "ORB_v3_SPMS"; // Comentario en las ordenes

input group "=== VISUALIZACION ==="
input bool   InpShowVisuals   = true;      // true=mostrar objetos en grafico, false=desactivar (backtest)
input color  InpColorTP       = clrLime;   // Color de la linea Take Profit
input color  InpColorSL       = clrRed;    // Color de la linea Stop Loss
input color  InpColorBE       = clrCyan;   // Color de la linea Breakeven
input color  InpColorRange    = clrOrange; // Color de las velas del rango ORB
input color  InpColorSession  = clrWhite;  // Color de la linea vertical de sesion

//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES                                              |
//+------------------------------------------------------------------+
CTrade   g_Trade;
double   g_PipSize        = 0.0;
int      g_PrevDay        = -1;
bool     g_RangeBuilt     = false;
bool     g_OrdersPlaced   = false;
bool     g_TradeDone      = false;
bool     g_BEApplied      = false;
bool     g_OppCancelled   = false;
double   g_RangeHigh      = 0.0;
double   g_RangeLow       = 0.0;
datetime g_RangeStartTime = 0;
datetime g_RangeEndTime   = 0;
ulong    g_TicketBuy      = 0;
ulong    g_TicketSell     = 0;
double   g_SPMS_Score     = 0.0;  // Score SPMS calculado cada dia
string   g_ObjPrefix      = "ORB_v3_SPMS_";

//+------------------------------------------------------------------+
//| OnInit                                                           |
//+------------------------------------------------------------------+
int OnInit()
{
   if(InpRangeCandles < 1)
      { Alert("Error: InpRangeCandles debe ser >= 1"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSL_Pips <= 0.0 || InpTP_Pips <= 0.0)
      { Alert("Error: InpSL_Pips e InpTP_Pips deben ser > 0"); return INIT_PARAMETERS_INCORRECT; }
   if(!InpUsePercentRisk && InpRiskUSD <= 0.0)
      { Alert("Error: InpRiskUSD debe ser > 0"); return INIT_PARAMETERS_INCORRECT; }
   if(InpUsePercentRisk && (InpRiskPercent <= 0.0 || InpRiskPercent > 20.0))
      { Alert("Error: InpRiskPercent debe estar entre 0.1 y 20.0"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSessionHour < 0 || InpSessionHour > 23)
      { Alert("Error: InpSessionHour debe ser entre 0 y 23"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSessionMinute < 0 || InpSessionMinute > 59)
      { Alert("Error: InpSessionMinute debe ser entre 0 y 59"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSPMS_VelasLookback < 2)
      { Alert("Error: InpSPMS_VelasLookback debe ser >= 2"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSPMS_PeriodoATR < 2)
      { Alert("Error: InpSPMS_PeriodoATR debe ser >= 2"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSPMS_UmbralScore <= 0.0 || InpSPMS_UmbralScore > 1.0)
      { Alert("Error: InpSPMS_UmbralScore debe estar entre 0.01 y 1.0"); return INIT_PARAMETERS_INCORRECT; }

   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetAsyncMode(false);
   g_Trade.SetTypeFilling(DetectFillingType());
   g_PipSize = _Point * 10.0;

   Print("════════════════════════════════════════════");
   Print("  ORB EA v3.00 SPMS XAUUSD — Iniciando");
   Print("════════════════════════════════════════════");
   PrintFormat("  Sesion    : %02d:%02d  |  Rango: %d velas", InpSessionHour, InpSessionMinute, InpRangeCandles);
   PrintFormat("  SL=%.1f | TP=%.1f | BE=%.1f (pips)", InpSL_Pips, InpTP_Pips, InpBE_Pips);
   PrintFormat("  SPMS activo: %s | Lookback=%d velas | PeriodoATR=%d | Umbral=%.2f",
               InpSPMS_Activo ? "SI" : "NO", InpSPMS_VelasLookback, InpSPMS_PeriodoATR, InpSPMS_UmbralScore);
   PrintFormat("  Magic #: %d | Riesgo: %s", InpMagicNumber,
               InpUsePercentRisk ? StringFormat("%.2f%%", InpRiskPercent) : StringFormat("$%.2f", InpRiskUSD));

   if(InpShowVisuals) DrawPanelInfo("INICIANDO");
   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| OnDeinit                                                         |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   CancelAllPendingOrders();
   DeleteAllObjects();
   Comment("");
   PrintFormat("ORB EA v3 SPMS detenido. Razon: %d", reason);
}

//+------------------------------------------------------------------+
//| OnTick                                                           |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime    now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   if(dt.day != g_PrevDay)
   {
      ResetDay(now, dt.day_of_week);
      g_PrevDay = dt.day;
   }

   if(!IsDayAllowed(dt.day_of_week))
   {
      if(InpShowVisuals) DrawPanelInfo("DIA NO PERMITIDO");
      return;
   }

   if(g_TradeDone)
   {
      if(InpShowVisuals) DrawPanelInfo("COMPLETADO");
      return;
   }

   if(!g_RangeBuilt)
   {
      if(now < g_RangeEndTime)
      {
         if(InpShowVisuals) DrawPanelInfo("DEFINIENDO RANGO...");
         return;
      }
      if(BuildRange())
      {
         g_RangeBuilt = true;
         // Calcular SPMS despues de completar el rango
         g_SPMS_Score = CalcularSPMS();
         PrintFormat("RANGO DEFINIDO | H=%.5f L=%.5f | SPMS_Score=%.4f",
                     g_RangeHigh, g_RangeLow, g_SPMS_Score);
         if(InpShowVisuals)
         {
            DrawSessionLine();
            DrawRangeLevels();
            ColorRangeCandles();
         }
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRange: sin velas validas. Saltando dia.");
         g_TradeDone = true;
         if(InpShowVisuals) DrawPanelInfo("SIN RANGO VALIDO");
      }
      return;
   }

   if(g_OrdersPlaced) ManageTrade();
   if(InpShowVisuals) DrawPanelInfo(GetStatusStr());
}

//+------------------------------------------------------------------+
//| CalcularSPMS — Session Pre-Momentum Slope                        |
//|  Pendiente de regresion lineal sobre los ultimos                 |
//|  InpSPMS_VelasLookback cierres, normalizada por ATR.            |
//|  Retorna score en [-1.0, +1.0].                                  |
//+------------------------------------------------------------------+
double CalcularSPMS()
{
   if(!InpSPMS_Activo) return 0.0;

   int n = InpSPMS_VelasLookback;

   // Las velas a leer empiezan DESPUES del rango
   // i=InpRangeCandles+1 es la vela previa al rango mas antigua
   // Recopilamos n cierres en orden cronologico: indice alto=antiguo
   double sumX  = 0.0, sumY  = 0.0;
   double sumXY = 0.0, sumX2 = 0.0;

   for(int i = 0; i < n; i++)
   {
      // bar_index: la vela mas reciente antes del rango = InpRangeCandles+1
      // la mas antigua = InpRangeCandles+n
      int barIdx = InpRangeCandles + n - i; // i=0 -> barra mas antigua
      double y   = iClose(_Symbol, _Period, barIdx);
      double x   = (double)i;
      sumX  += x;
      sumY  += y;
      sumXY += x * y;
      sumX2 += x * x;
   }

   double denom = (double)n * sumX2 - sumX * sumX;
   if(MathAbs(denom) < 1e-12) return 0.0;

   double slope = ((double)n * sumXY - sumX * sumY) / denom;

   // Normalizar por ATR para hacerlo adimensional
   int    atrHandle = iATR(_Symbol, _Period, InpSPMS_PeriodoATR);
   if(atrHandle == INVALID_HANDLE) return 0.0;

   double atrBuf[];
   ArraySetAsSeries(atrBuf, true);
   if(CopyBuffer(atrHandle, 0, InpRangeCandles + 1, 1, atrBuf) <= 0)
   {
      IndicatorRelease(atrHandle);
      return 0.0;
   }
   IndicatorRelease(atrHandle);

   double atr = atrBuf[0];
   if(atr < _Point * 10) return 0.0;

   double score = slope / atr;
   return MathMax(-1.0, MathMin(1.0, score));
}

//+------------------------------------------------------------------+
//| ResetDay                                                         |
//+------------------------------------------------------------------+
void ResetDay(datetime now, int dayOfWeek)
{
   CancelAllPendingOrders();
   DeleteDayObjects();
   g_RangeHigh    = 0.0;
   g_RangeLow     = 0.0;
   g_RangeBuilt   = false;
   g_OrdersPlaced = false;
   g_TradeDone    = false;
   g_BEApplied    = false;
   g_OppCancelled = false;
   g_TicketBuy    = 0;
   g_TicketSell   = 0;
   g_SPMS_Score   = 0.0;

   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight + InpSessionHour * 3600 + InpSessionMinute * 60;
   g_RangeEndTime       = g_RangeStartTime + (long)InpRangeCandles * PeriodSeconds(_Period);

   if(IsDayAllowed(dayOfWeek))
      PrintFormat("Nuevo dia | Sesion: %s -> Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
}

//+------------------------------------------------------------------+
//| BuildRange                                                       |
//+------------------------------------------------------------------+
bool BuildRange()
{
   double hi    = 0.0;
   double lo    = DBL_MAX;
   int    count = 0;
   int    total = iBars(_Symbol, _Period);

   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);
      if(t >= g_RangeEndTime)  continue;
      if(t < g_RangeStartTime) break;
      double barHi = iHigh(_Symbol, _Period, i);
      double barLo = iLow (_Symbol, _Period, i);
      if(barHi > hi) hi = barHi;
      if(barLo < lo) lo = barLo;
      count++;
   }
   PrintFormat("BuildRange: %d vela(s) en [%s - %s]", count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));
   if(count == 0 || hi <= lo || hi == 0.0) return false;
   g_RangeHigh = hi;
   g_RangeLow  = lo;
   return true;
}

//+------------------------------------------------------------------+
//| PlacePendingOrders — aplica filtro SPMS + InpTradeDirection      |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   // --- Determinar direcciones permitidas por InpTradeDirection ---
   bool baseAllowBuy  = (InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY);
   bool baseAllowSell = (InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY);

   // --- Aplicar filtro SPMS sobre las direcciones base ---
   bool finalAllowBuy  = baseAllowBuy;
   bool finalAllowSell = baseAllowSell;

   if(InpSPMS_Activo)
   {
      // Score > +umbral: presion alcista -> bloquear SELL
      if(g_SPMS_Score >  InpSPMS_UmbralScore) finalAllowSell = false;
      // Score < -umbral: presion bajista -> bloquear BUY
      if(g_SPMS_Score < -InpSPMS_UmbralScore) finalAllowBuy  = false;
      // Zona neutra [-umbral, +umbral]: respetar InpTradeDirection sin cambios
      PrintFormat("SPMS filtro | Score=%.4f | Umbral=%.2f | BUY=%s SELL=%s",
                  g_SPMS_Score, InpSPMS_UmbralScore,
                  finalAllowBuy  ? "SI" : "NO",
                  finalAllowSell ? "SI" : "NO");
   }

   if(!finalAllowBuy && !finalAllowSell)
   {
      Print("SPMS: ninguna direccion permitida para hoy. Saltando.");
      g_TradeDone = true;
      return;
   }

   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist  = InpSL_Pips * g_PipSize;
   double tpDist  = InpTP_Pips * g_PipSize;
   double minDist = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots    = CalculateLotSize();
   bool   placed  = false;

   if(lots <= 0.0)
   {
      Print("PlacePendingOrders: lotaje invalido. Saltando dia.");
      g_TradeDone = true;
      return;
   }

   // BUY STOP
   if(finalAllowBuy && g_RangeHigh > ask + minDist)
   {
      double entry = NormalizeDouble(g_RangeHigh, _Digits);
      double sl    = NormalizeDouble(entry - slDist, _Digits);
      double tp    = NormalizeDouble(entry + tpDist, _Digits);
      if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketBuy = g_Trade.ResultOrder();
         PrintFormat("BUY STOP #%s E=%.5f SL=%.5f TP=%.5f Lots=%.2f",
                     (string)g_TicketBuy, entry, sl, tp, lots);
         placed = true;
      }
      else PrintFormat("Error BUY STOP: %s (%d)",
                       g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   }
   else if(finalAllowBuy)
      PrintFormat("BUY STOP omitido: precio demasiado cerca del High (ask=%.5f high=%.5f)", ask, g_RangeHigh);

   // SELL STOP
   if(finalAllowSell && g_RangeLow < bid - minDist)
   {
      double entry = NormalizeDouble(g_RangeLow, _Digits);
      double sl    = NormalizeDouble(entry + slDist, _Digits);
      double tp    = NormalizeDouble(entry - tpDist, _Digits);
      if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketSell = g_Trade.ResultOrder();
         PrintFormat("SELL STOP #%s E=%.5f SL=%.5f TP=%.5f Lots=%.2f",
                     (string)g_TicketSell, entry, sl, tp, lots);
         placed = true;
      }
      else PrintFormat("Error SELL STOP: %s (%d)",
                       g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   }
   else if(finalAllowSell)
      PrintFormat("SELL STOP omitido: precio demasiado cerca del Low (bid=%.5f low=%.5f)", bid, g_RangeLow);

   g_OrdersPlaced = placed;
   if(!placed) { Print("Sin ordenes colocadas. Dia terminado."); g_TradeDone = true; }
}

//+------------------------------------------------------------------+
//| ManageTrade                                                      |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();
   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      {
         CancelAllPendingOrders();
         g_OppCancelled = true;
         PrintFormat("Breakout activado! Posicion #%s | Orden opuesta cancelada.", (string)posTicket);
         if(InpShowVisuals) DrawTradeLevels(posTicket);
      }
      if(!g_BEApplied && InpBE_Pips > 0.0) ApplyBreakeven(posTicket);
      return;
   }
   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay)
      {
         g_TradeDone = true;
         DeleteTradeLines();
         Print("Posicion cerrada. Dia completado.");
      }
      else
      {
         g_OppCancelled = false; g_BEApplied = false;
         g_TicketBuy = 0; g_TicketSell = 0;
         DeleteTradeLines();
         PlacePendingOrders();
      }
      return;
   }
   bool buyPending  = (g_TicketBuy  > 0 && IsOrderPending(g_TicketBuy));
   bool sellPending = (g_TicketSell > 0 && IsOrderPending(g_TicketSell));
   if(!buyPending && !sellPending)
   { g_TradeDone = true; Print("Ordenes expiradas. Dia terminado."); }
}

//+------------------------------------------------------------------+
//| ApplyBreakeven                                                   |
//+------------------------------------------------------------------+
void ApplyBreakeven(ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;
   ENUM_POSITION_TYPE posType    = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   double             openPrice  = PositionGetDouble(POSITION_PRICE_OPEN);
   double             currentSL  = PositionGetDouble(POSITION_SL);
   double             currentTP  = PositionGetDouble(POSITION_TP);
   double             beDistance = InpBE_Pips * g_PipSize;
   double             bid        = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double             ask        = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double             newSL      = 0.0;
   bool               doModify   = false;
   if(posType == POSITION_TYPE_BUY)
   {
      if(bid >= openPrice + beDistance)
      { newSL = NormalizeDouble(openPrice, _Digits); if(newSL > currentSL) doModify = true; }
   }
   else
   {
      if(ask <= openPrice - beDistance)
      { newSL = NormalizeDouble(openPrice, _Digits); if(currentSL == 0.0 || newSL < currentSL) doModify = true; }
   }
   if(doModify)
   {
      if(g_Trade.PositionModify(ticket, newSL, currentTP))
      {
         g_BEApplied = true;
         PrintFormat("BREAKEVEN aplicado | #%s Nuevo SL=%.5f", (string)ticket, newSL);
         if(InpShowVisuals) DrawBELine(newSL);
      }
      else PrintFormat("Error BE: %s (%d)", g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
   }
}

//+------------------------------------------------------------------+
//| CalculateLotSize                                                 |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk ? (balance * InpRiskPercent / 100.0) : InpRiskUSD;
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(tickSize <= 0.0 || tickValue <= 0.0) { Print("CalculateLotSize: tick info invalida"); return 0.0; }
   double valuePerPip = tickValue * (g_PipSize / tickSize);
   if(valuePerPip <= 0.0) return 0.0;
   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);
   PrintFormat("Lotaje: %.2f (Riesgo=$%.2f | Balance=$%.2f)", lots, riskAmount, balance);
   return lots;
}

//+------------------------------------------------------------------+
//| FindOpenPosition                                                 |
//+------------------------------------------------------------------+
ulong FindOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      ulong ticket = PositionGetTicket(i);
      if(PositionGetString(POSITION_SYMBOL) == _Symbol &&
         PositionGetInteger(POSITION_MAGIC) == (long)InpMagicNumber)
         return ticket;
   }
   return 0;
}

//+------------------------------------------------------------------+
//| IsOrderPending                                                   |
//+------------------------------------------------------------------+
bool IsOrderPending(ulong ticket)
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
      if(OrderGetTicket(i) == ticket) return true;
   return false;
}

//+------------------------------------------------------------------+
//| CancelAllPendingOrders                                           |
//+------------------------------------------------------------------+
void CancelAllPendingOrders()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      ulong ticket = OrderGetTicket(i);
      if(OrderGetInteger(ORDER_MAGIC) == (long)InpMagicNumber &&
         OrderGetString(ORDER_SYMBOL) == _Symbol)
      {
         if(g_Trade.OrderDelete(ticket)) Print("Orden cancelada: #", (string)ticket);
         else PrintFormat("Error cancelando #%s: %s (%d)", (string)ticket,
                          g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
   }
   g_TicketBuy  = 0;
   g_TicketSell = 0;
}

//+------------------------------------------------------------------+
//| IsDayAllowed                                                     |
//+------------------------------------------------------------------+
bool IsDayAllowed(int dow)
{
   switch(dow)
   {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
      default: return false;
   }
}

//+------------------------------------------------------------------+
//| DetectFillingType                                                |
//+------------------------------------------------------------------+
ENUM_ORDER_TYPE_FILLING DetectFillingType()
{
   uint filling = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((filling & SYMBOL_FILLING_FOK) != 0) return ORDER_FILLING_FOK;
   if((filling & SYMBOL_FILLING_IOC) != 0) return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
}

//+------------------------------------------------------------------+
//| GetStatusStr                                                     |
//+------------------------------------------------------------------+
string GetStatusStr()
{
   if(g_TradeDone)    return "COMPLETADO";
   if(g_OppCancelled) return "EN POSICION";
   if(g_OrdersPlaced) return "ESPERANDO RUPTURA";
   if(g_RangeBuilt)   return "RANGO DEFINIDO";
   return "DEFINIENDO RANGO";
}

