//+------------------------------------------------------------------+
//| OnTick                                                           |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime    now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   if(dt.day != g_PrevDay)
   {
      ResetDay(now, dt.day_of_week);
      g_PrevDay = dt.day;
   }

   if(!IsDayAllowed(dt.day_of_week))
   {
      if(InpShowVisuals) DrawPanelInfo("DIA NO PERMITIDO");
      return;
   }

   if(g_TradeDone)
   {
      if(InpShowVisuals) DrawPanelInfo("COMPLETADO");
      return;
   }

   if(!g_RangeBuilt)
   {
      if(now < g_RangeEndTime)
      {
         if(InpShowVisuals) DrawPanelInfo("DEFINIENDO RANGO...");
         return;
      }
      if(BuildRange())
      {
         g_RangeBuilt  = true;
         g_PSRP_Posicion = CalcularPSRP();
         PrintFormat("RANGO DEFINIDO | H=%.5f L=%.5f | PSRP_Posicion=%.4f",
                     g_RangeHigh, g_RangeLow, g_PSRP_Posicion);
         if(InpShowVisuals)
         {
            DrawSessionLine();
            DrawRangeLevels();
            ColorRangeCandles();
         }
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRange: sin velas validas. Saltando dia.");
         g_TradeDone = true;
         if(InpShowVisuals) DrawPanelInfo("SIN RANGO VALIDO");
      }
      return;
   }

   if(g_OrdersPlaced) ManageTrade();
   if(InpShowVisuals) DrawPanelInfo(GetStatusStr());
}

//+------------------------------------------------------------------+
//| CalcularPSRP — Previous Session Range Position                   |
//|  Recorre las InpPSRP_VelasLookback velas anteriores al rango,   |
//|  obtiene su High y Low, y calcula donde esta el precio actual    |
//|  dentro de ese rango: 0.0=fondo, 1.0=techo.                     |
//+------------------------------------------------------------------+
double CalcularPSRP()
{
   if(!InpPSRP_Activo) return 0.5; // neutral si desactivado

   int    startBar  = InpRangeCandles + 1; // barra justo detras del rango
   double prevHigh  = 0.0;
   double prevLow   = DBL_MAX;

   for(int i = startBar; i < startBar + InpPSRP_VelasLookback; i++)
   {
      double h = iHigh(_Symbol, _Period, i);
      double l = iLow (_Symbol, _Period, i);
      if(h > prevHigh) prevHigh = h;
      if(l < prevLow)  prevLow  = l;
   }

   double rango = prevHigh - prevLow;
   if(rango < _Point * 20)
   {
      Print("PSRP: rango de sesion previa demasiado pequeno, retornando 0.5 (neutral)");
      return 0.5;
   }

   double precio = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double pos    = (precio - prevLow) / rango;
   pos = MathMax(0.0, MathMin(1.0, pos));

   PrintFormat("PSRP | PrevHigh=%.5f PrevLow=%.5f Precio=%.5f Posicion=%.4f",
               prevHigh, prevLow, precio, pos);
   return pos;
}

//+------------------------------------------------------------------+
//| ResetDay                                                         |
//+------------------------------------------------------------------+
void ResetDay(datetime now, int dayOfWeek)
{
   CancelAllPendingOrders();
   DeleteDayObjects();
   g_RangeHigh     = 0.0;
   g_RangeLow      = 0.0;
   g_RangeBuilt    = false;
   g_OrdersPlaced  = false;
   g_TradeDone     = false;
   g_BEApplied     = false;
   g_OppCancelled  = false;
   g_TicketBuy     = 0;
   g_TicketSell    = 0;
   g_PSRP_Posicion = 0.5;

   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight + InpSessionHour * 3600 + InpSessionMinute * 60;
   g_RangeEndTime       = g_RangeStartTime + (long)InpRangeCandles * PeriodSeconds(_Period);

   if(IsDayAllowed(dayOfWeek))
      PrintFormat("Nuevo dia | Sesion: %s -> Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
}

//+------------------------------------------------------------------+
//| BuildRange                                                       |
//+------------------------------------------------------------------+
bool BuildRange()
{
   double hi = 0.0, lo = DBL_MAX;
   int count = 0, total = iBars(_Symbol, _Period);
   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);
      if(t >= g_RangeEndTime) continue; if(t < g_RangeStartTime) break;
      double bH = iHigh(_Symbol,_Period,i); double bL = iLow(_Symbol,_Period,i);
      if(bH > hi) hi = bH; if(bL < lo) lo = bL; count++;
   }
   PrintFormat("BuildRange: %d vela(s) en [%s - %s]", count,
               TimeToString(g_RangeStartTime,TIME_MINUTES), TimeToString(g_RangeEndTime,TIME_MINUTES));
   if(count == 0 || hi <= lo || hi == 0.0) return false;
   g_RangeHigh = hi; g_RangeLow = lo;
   return true;
}

//+------------------------------------------------------------------+
//| PlacePendingOrders — aplica filtro PSRP + InpTradeDirection      |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   bool baseAllowBuy  = (InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY);
   bool baseAllowSell = (InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY);
   bool finalAllowBuy  = baseAllowBuy;
   bool finalAllowSell = baseAllowSell;

   if(InpPSRP_Activo)
   {
      // Posicion alta (> UmbralSuperior): precio en tercio alto -> bloquear SELL
      if(g_PSRP_Posicion > InpPSRP_UmbralSuperior) finalAllowSell = false;
      // Posicion baja (< UmbralInferior): precio en tercio bajo -> bloquear BUY
      if(g_PSRP_Posicion < InpPSRP_UmbralInferior) finalAllowBuy  = false;
      // Zona media [UmbralInferior, UmbralSuperior]: respetar InpTradeDirection
      PrintFormat("PSRP filtro | Posicion=%.4f | Sup=%.2f Inf=%.2f | BUY=%s SELL=%s",
                  g_PSRP_Posicion, InpPSRP_UmbralSuperior, InpPSRP_UmbralInferior,
                  finalAllowBuy ? "SI" : "NO", finalAllowSell ? "SI" : "NO");
   }

   if(!finalAllowBuy && !finalAllowSell)
   {
      Print("PSRP: ninguna direccion permitida para hoy. Saltando.");
      g_TradeDone = true;
      return;
   }

   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist  = InpSL_Pips * g_PipSize;
   double tpDist  = InpTP_Pips * g_PipSize;
   double minDist = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots    = CalculateLotSize();
   bool   placed  = false;

   if(lots <= 0.0) { Print("PlacePendingOrders: lotaje invalido."); g_TradeDone=true; return; }

   if(finalAllowBuy && g_RangeHigh > ask + minDist)
   {
      double entry=NormalizeDouble(g_RangeHigh,_Digits);
      double sl=NormalizeDouble(entry-slDist,_Digits); double tp=NormalizeDouble(entry+tpDist,_Digits);
      if(g_Trade.BuyStop(lots,entry,_Symbol,sl,tp,ORDER_TIME_GTC,0,InpComment))
      { g_TicketBuy=g_Trade.ResultOrder(); PrintFormat("BUY STOP #%s E=%.5f",(string)g_TicketBuy,entry); placed=true; }
      else PrintFormat("Error BUY STOP: %s (%d)",g_Trade.ResultRetcodeDescription(),g_Trade.ResultRetcode());
   }
   else if(finalAllowBuy)
      PrintFormat("BUY STOP omitido: precio cerca del High");

   if(finalAllowSell && g_RangeLow < bid - minDist)
   {
      double entry=NormalizeDouble(g_RangeLow,_Digits);
      double sl=NormalizeDouble(entry+slDist,_Digits); double tp=NormalizeDouble(entry-tpDist,_Digits);
      if(g_Trade.SellStop(lots,entry,_Symbol,sl,tp,ORDER_TIME_GTC,0,InpComment))
      { g_TicketSell=g_Trade.ResultOrder(); PrintFormat("SELL STOP #%s E=%.5f",(string)g_TicketSell,entry); placed=true; }
      else PrintFormat("Error SELL STOP: %s (%d)",g_Trade.ResultRetcodeDescription(),g_Trade.ResultRetcode());
   }
   else if(finalAllowSell)
      PrintFormat("SELL STOP omitido: precio cerca del Low");

   g_OrdersPlaced = placed;
   if(!placed) { Print("Sin ordenes colocadas. Dia terminado."); g_TradeDone=true; }
}

//+------------------------------------------------------------------+
//| ManageTrade                                                      |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();
   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      { CancelAllPendingOrders(); g_OppCancelled=true;
        PrintFormat("Breakout activado! #%s",(string)posTicket);
        if(InpShowVisuals) DrawTradeLevels(posTicket); }
      if(!g_BEApplied && InpBE_Pips>0.0) ApplyBreakeven(posTicket);
      return;
   }
   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay) { g_TradeDone=true; DeleteTradeLines(); Print("Dia completado."); }
      else { g_OppCancelled=false; g_BEApplied=false; g_TicketBuy=0; g_TicketSell=0; DeleteTradeLines(); PlacePendingOrders(); }
      return;
   }
   bool bP=(g_TicketBuy>0&&IsOrderPending(g_TicketBuy)); bool sP=(g_TicketSell>0&&IsOrderPending(g_TicketSell));
   if(!bP&&!sP) { g_TradeDone=true; Print("Ordenes expiradas. Dia terminado."); }
}

//+------------------------------------------------------------------+
//| ApplyBreakeven                                                   |
//+------------------------------------------------------------------+
void ApplyBreakeven(ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;
   ENUM_POSITION_TYPE pt=(ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   double op=PositionGetDouble(POSITION_PRICE_OPEN); double cSL=PositionGetDouble(POSITION_SL);
   double cTP=PositionGetDouble(POSITION_TP); double beDist=InpBE_Pips*g_PipSize;
   double bid=SymbolInfoDouble(_Symbol,SYMBOL_BID); double ask=SymbolInfoDouble(_Symbol,SYMBOL_ASK);
   double newSL=0.0; bool doMod=false;
   if(pt==POSITION_TYPE_BUY) { if(bid>=op+beDist) { newSL=NormalizeDouble(op,_Digits); if(newSL>cSL) doMod=true; } }
   else { if(ask<=op-beDist) { newSL=NormalizeDouble(op,_Digits); if(cSL==0.0||newSL<cSL) doMod=true; } }
   if(doMod)
   {
      if(g_Trade.PositionModify(ticket,newSL,cTP))
      { g_BEApplied=true; PrintFormat("BE aplicado #%s SL=%.5f",(string)ticket,newSL); if(InpShowVisuals) DrawBELine(newSL); }
      else PrintFormat("Error BE: %s (%d)",g_Trade.ResultRetcodeDescription(),g_Trade.ResultRetcode());
   }
}

//+------------------------------------------------------------------+
//| CalculateLotSize                                                 |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance=AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount=InpUsePercentRisk?(balance*InpRiskPercent/100.0):InpRiskUSD;
   double tickValue=SymbolInfoDouble(_Symbol,SYMBOL_TRADE_TICK_VALUE);
   double tickSize=SymbolInfoDouble(_Symbol,SYMBOL_TRADE_TICK_SIZE);
   if(tickSize<=0.0||tickValue<=0.0) return 0.0;
   double vpp=tickValue*(g_PipSize/tickSize); if(vpp<=0.0) return 0.0;
   double lots=riskAmount/(InpSL_Pips*vpp);
   double minL=SymbolInfoDouble(_Symbol,SYMBOL_VOLUME_MIN); double maxL=SymbolInfoDouble(_Symbol,SYMBOL_VOLUME_MAX);
   double step=SymbolInfoDouble(_Symbol,SYMBOL_VOLUME_STEP);
   lots=MathFloor(lots/step)*step; lots=MathMax(lots,minL); lots=MathMin(lots,maxL);
   return lots;
}

//+------------------------------------------------------------------+
//| FindOpenPosition / IsOrderPending / CancelAllPendingOrders       |
//+------------------------------------------------------------------+
ulong FindOpenPosition()
{
   for(int i=PositionsTotal()-1;i>=0;i--)
   { ulong t=PositionGetTicket(i); if(PositionGetString(POSITION_SYMBOL)==_Symbol&&PositionGetInteger(POSITION_MAGIC)==(long)InpMagicNumber) return t; }
   return 0;
}
bool IsOrderPending(ulong ticket)
{ for(int i=OrdersTotal()-1;i>=0;i--) if(OrderGetTicket(i)==ticket) return true; return false; }
void CancelAllPendingOrders()
{
   for(int i=OrdersTotal()-1;i>=0;i--)
   { ulong t=OrderGetTicket(i); if(OrderGetInteger(ORDER_MAGIC)==(long)InpMagicNumber&&OrderGetString(ORDER_SYMBOL)==_Symbol)
     { if(g_Trade.OrderDelete(t)) Print("Orden cancelada: #",(string)t);
       else PrintFormat("Error cancelando #%s: %s",(string)t,g_Trade.ResultRetcodeDescription()); } }
   g_TicketBuy=0; g_TicketSell=0;
}

//+------------------------------------------------------------------+
//| IsDayAllowed / DetectFillingType / GetStatusStr                  |
//+------------------------------------------------------------------+
bool IsDayAllowed(int dow)
{ switch(dow){ case 0:return InpAllowSunday; case 1:return InpAllowMonday; case 2:return InpAllowTuesday;
  case 3:return InpAllowWednesday; case 4:return InpAllowThursday; case 5:return InpAllowFriday;
  case 6:return InpAllowSaturday; default:return false; } }
ENUM_ORDER_TYPE_FILLING DetectFillingType()
{ uint f=(uint)SymbolInfoInteger(_Symbol,SYMBOL_FILLING_MODE);
  if((f&SYMBOL_FILLING_FOK)!=0) return ORDER_FILLING_FOK;
  if((f&SYMBOL_FILLING_IOC)!=0) return ORDER_FILLING_IOC; return ORDER_FILLING_RETURN; }
string GetStatusStr()
{ if(g_TradeDone) return "COMPLETADO"; if(g_OppCancelled) return "EN POSICION";
  if(g_OrdersPlaced) return "ESPERANDO RUPTURA"; if(g_RangeBuilt) return "RANGO DEFINIDO"; return "DEFINIENDO RANGO"; }

