void ColorRangeCandles()
{ int total=iBars(_Symbol,_Period);
  for(int i=1;i<total;i++) { datetime t=iTime(_Symbol,_Period,i); if(t>=g_RangeEndTime)continue; if(t<g_RangeStartTime)break;
    string name=g_ObjPrefix+"Candle_"+TimeToString(t,TIME_DATE|TIME_MINUTES); if(ObjectFind(0,name)>=0)ObjectDelete(0,name);
    double o=iOpen(_Symbol,_Period,i); double c=iClose(_Symbol,_Period,i);
    ObjectCreate(0,name,OBJ_RECTANGLE,0,t,MathMax(o,c),t+PeriodSeconds(_Period)-1,MathMin(o,c));
    ObjectSetInteger(0,name,OBJPROP_COLOR,InpColorRange);ObjectSetInteger(0,name,OBJPROP_BGCOLOR,InpColorRange);
    ObjectSetInteger(0,name,OBJPROP_FILL,true);ObjectSetInteger(0,name,OBJPROP_WIDTH,1);
    ObjectSetInteger(0,name,OBJPROP_SELECTABLE,false);ObjectSetInteger(0,name,OBJPROP_HIDDEN,true); } ChartRedraw(0); }

void DrawTradeLevels(ulong ticket)
{ if(!PositionSelectByTicket(ticket))return;
  double sl=PositionGetDouble(POSITION_SL); double tp=PositionGetDouble(POSITION_TP);
  CreateHLine(g_ObjPrefix+"TP",tp,InpColorTP,2,STYLE_SOLID,"TP");
  CreateHLine(g_ObjPrefix+"SL",sl,InpColorSL,2,STYLE_SOLID,"SL");
  if(InpBE_Pips>0.0&&!g_BEApplied) { double op=PositionGetDouble(POSITION_PRICE_OPEN);
    ENUM_POSITION_TYPE pt=(ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
    double beTrig=NormalizeDouble(pt==POSITION_TYPE_BUY?op+InpBE_Pips*g_PipSize:op-InpBE_Pips*g_PipSize,_Digits);
    CreateHLine(g_ObjPrefix+"BE_Trigger",beTrig,InpColorBE,1,STYLE_DASH,"BE Trigger"); } ChartRedraw(0); }

void DrawBELine(double price)
{ string tn=g_ObjPrefix+"BE_Trigger"; string tl=tn+"_lbl";
  if(ObjectFind(0,tn)>=0)ObjectDelete(0,tn); if(ObjectFind(0,tl)>=0)ObjectDelete(0,tl);
  CreateHLine(g_ObjPrefix+"BE_Applied",price,InpColorBE,2,STYLE_DASH,"BE"); ChartRedraw(0); }

void DeleteTradeLines()
{ string arr[]={"TP","SL","BE_Trigger","BE_Applied"};
  for(int i=0;i<ArraySize(arr);i++) { string n=g_ObjPrefix+arr[i]; string nl=n+"_lbl";
    if(ObjectFind(0,n)>=0)ObjectDelete(0,n); if(ObjectFind(0,nl)>=0)ObjectDelete(0,nl); } ChartRedraw(0); }

void DeleteDayObjects()
{ int total=ObjectsTotal(0); for(int i=total-1;i>=0;i--)
  { string name=ObjectName(0,i); if(StringFind(name,g_ObjPrefix)==0)
    { if(StringFind(name,"Panel")>=0||StringFind(name,"Edge")>=0)continue; ObjectDelete(0,name); } } ChartRedraw(0); }

void DeleteAllObjects()
{ int total=ObjectsTotal(0); for(int i=total-1;i>=0;i--)
  { string name=ObjectName(0,i); if(StringFind(name,g_ObjPrefix)==0)ObjectDelete(0,name); } ChartRedraw(0); }

void DrawLabel(string name,string text,int x,int y,color clr,int fontSize,bool bold)
{ if(ObjectFind(0,name)<0)ObjectCreate(0,name,OBJ_LABEL,0,0,0);
  ObjectSetString(0,name,OBJPROP_TEXT,text); ObjectSetInteger(0,name,OBJPROP_CORNER,CORNER_LEFT_UPPER);
  ObjectSetInteger(0,name,OBJPROP_XDISTANCE,x); ObjectSetInteger(0,name,OBJPROP_YDISTANCE,y);
  ObjectSetInteger(0,name,OBJPROP_COLOR,clr); ObjectSetInteger(0,name,OBJPROP_FONTSIZE,fontSize);
