  DrawLabel(g_ObjPrefix+"P_Title","  ORB EA v3.0 | XAUUSD | ORCA",  14,36, clrGold,     10,true);
  DrawLabel(g_ObjPrefix+"P_Div1","─────────────────────────────",   14,50, C'60,80,100', 8,false);
