display_content.json_block:
{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                         ORB_BreakoutEA_v3_ORCA_XAUUSD.mq5       |
//|            Opening Range Breakout EA v3.0 — Filtro ORCA          |
//|                    Jose's Trading Suite — Abril 2026             |
//+------------------------------------------------------------------+
//|  FILTRO ORCA: ORB Range Compression Asymmetry                    |
//|  Analiza la estructura interna de las velas del rango ORB para   |
//|  detectar hacia que lado esta "comprimida" la presion.           |
//|  Dos componentes combinados en un score unico:                   |
//|   1) BullPressure: promedio de (cierre-apertura)/(high-low)      |
//|      por vela del rango. Refleja dominio comprador vs vendedor.  |
//|   2) MidBias: sesgo del midpoint del rango respecto a la         |
//|      primera apertura. Refleja donde se concentro el precio.     |
//|  Score = InpORCA_PesoBullPressure*BP + (1-peso)*MidBias          |
//|   Score > +InpORCA_UmbralScore => presion alcista -> BUY STOP    |
//|   Score < -InpORCA_UmbralScore => presion bajista -> SELL STOP   |
//|   entre ambos umbrales         => ambas ordenes (DIR_BOTH)       |
//|                                                                  |
//|  PARAMETROS NUEVOS vs v2.0:                                      |
//|   InpORCA_Activo          — activa/desactiva el filtro           |
//|   InpORCA_PesoBullPressure — peso del componente BullPressure    |
//|                              (1-peso va a MidBias) [0.30..0.80]  |
//|   InpORCA_UmbralScore     — umbral de activacion del filtro      |
//|                              [0.05..0.40]                        |
//|                                                                  |
//|  VENTAJA: cero lookback externo, cero indicadores MT5.           |
//|  Usa solo las velas ya calculadas en BuildRange().               |
//+------------------------------------------------------------------+
#property copyright   "Jose's Trading Suite"
#property link        ""
#property version     "3.00"
#property description "ORB EA v3 ORCA XAUUSD — Filtro ORB Range Compression Asymmetry"

#include <Trade\Trade.mqh>

//+------------------------------------------------------------------+
//|  ENUM DE DIRECCION                                               |
//+------------------------------------------------------------------+
enum ENUM_ORB_DIRECTION
{
   DIR_BOTH      = 0,  // Ambos — BUY STOP + SELL STOP
   DIR_BUY_ONLY  = 1,  // Solo compras — BUY STOP en el High
   DIR_SELL_ONLY = 2   // Solo ventas  — SELL STOP en el Low
};

//+------------------------------------------------------------------+
//|  PARAMETROS DE ENTRADA                                           |
//+------------------------------------------------------------------+

input group "=== CONFIGURACION DEL RANGO ORB ==="
input int    InpRangeCandles  = 4;     // Numero de velas del rango inicial
input int    InpSessionHour   = 17;    // Hora inicio sesion (hora servidor)
input int    InpSessionMinute = 0;     // Minutos inicio sesion

input group "=== GESTION DE RIESGO ==="
input double InpTP_Pips       = 130.0; // Take Profit en pips
input double InpSL_Pips       = 60.0;  // Stop Loss en pips
input double InpBE_Pips       = 0.0;   // Breakeven trigger en pips (0=desactivado)
input double InpRiskUSD       = 25.0;  // Riesgo en USD por operacion
input bool   InpUsePercentRisk = false; // true=usar % del balance, false=USD fijo
input double InpRiskPercent   = 1.0;   // Riesgo en % si InpUsePercentRisk=true

input group "=== DIAS PERMITIDOS ==="
input bool   InpAllowMonday    = true;  // Permitir operaciones el Lunes
input bool   InpAllowTuesday   = true;  // Permitir operaciones el Martes
input bool   InpAllowWednesday = true;  // Permitir operaciones el Miercoles
input bool   InpAllowThursday  = true;  // Permitir operaciones el Jueves
input bool   InpAllowFriday    = true;  // Permitir operaciones el Viernes
input bool   InpAllowSaturday  = false; // Permitir operaciones el Sabado
input bool   InpAllowSunday    = false; // Permitir operaciones el Domingo

input group "=== FILTRO ORCA — ORB Range Compression Asymmetry ==="
input bool   InpORCA_Activo           = true; // true=filtro activo, false=desactivado
input double InpORCA_PesoBullPressure = 0.60; // Peso del componente BullPressure en el score [0.30..0.80]. El resto va a MidBias.
input double InpORCA_UmbralScore      = 0.15; // Score minimo para forzar una direccion [0.05..0.40]. Zona neutra=[-umbral,+umbral]

input group "=== CONFIGURACION GENERAL ==="
input ENUM_ORB_DIRECTION InpTradeDirection = DIR_BOTH; // Direccion base: Ambos/Solo Compras/Solo Ventas
input bool   InpOnlyOnePerDay = true;      // Solo un trade por dia
input int    InpMagicNumber   = 20260503;  // Magic Number unico del EA
input string InpComment       = "ORB_v3_ORCA"; // Comentario en las ordenes

input group "=== VISUALIZACION ==="
input bool   InpShowVisuals   = true;      // true=mostrar objetos en grafico, false=desactivar (backtest)
input color  InpColorTP       = clrLime;   // Color de la linea Take Profit
input color  InpColorSL       = clrRed;    // Color de la linea Stop Loss
input color  InpColorBE       = clrCyan;   // Color de la linea Breakeven
input color  InpColorRange    = clrOrange; // Color de las velas del rango ORB
input color  InpColorSession  = clrWhite;  // Color de la linea vertical de sesion

//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES                                              |
//+------------------------------------------------------------------+
CTrade   g_Trade;
double   g_PipSize          = 0.0;
int      g_PrevDay          = -1;
bool     g_RangeBuilt       = false;
bool     g_OrdersPlaced     = false;
bool     g_TradeDone        = false;
bool     g_BEApplied        = false;
bool     g_OppCancelled     = false;
double   g_RangeHigh        = 0.0;
double   g_RangeLow         = 0.0;
datetime g_RangeStartTime   = 0;
datetime g_RangeEndTime     = 0;
ulong    g_TicketBuy        = 0;
ulong    g_TicketSell       = 0;
double   g_ORCA_Score       = 0.0;  // Score ORCA calculado cada dia
double   g_ORCA_BullPressure = 0.0; // Componente BP (para mostrar en panel)
double   g_ORCA_MidBias     = 0.0; // Componente MB (para mostrar en panel)
string   g_ObjPrefix        = "ORB_v3_ORCA_";

//+------------------------------------------------------------------+
//| OnInit                                                           |
//+------------------------------------------------------------------+
int OnInit()
{
   if(InpRangeCandles < 1)
      { Alert("Error: InpRangeCandles debe ser >= 1"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSL_Pips <= 0.0 || InpTP_Pips <= 0.0)
      { Alert("Error: InpSL_Pips e InpTP_Pips deben ser > 0"); return INIT_PARAMETERS_INCORRECT; }
   if(!InpUsePercentRisk && InpRiskUSD <= 0.0)
      { Alert("Error: InpRiskUSD debe ser > 0"); return INIT_PARAMETERS_INCORRECT; }
   if(InpUsePercentRisk && (InpRiskPercent <= 0.0 || InpRiskPercent > 20.0))
      { Alert("Error: InpRiskPercent debe estar entre 0.1 y 20.0"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSessionHour < 0 || InpSessionHour > 23)
      { Alert("Error: InpSessionHour debe ser entre 0 y 23"); return INIT_PARAMETERS_INCORRECT; }
   if(InpSessionMinute < 0 || InpSessionMinute > 59)
      { Alert("Error: InpSessionMinute debe ser entre 0 y 59"); return INIT_PARAMETERS_INCORRECT; }
   if(InpORCA_PesoBullPressure < 0.0 || InpORCA_PesoBullPressure > 1.0)
      { Alert("Error: InpORCA_PesoBullPressure debe estar entre 0.0 y 1.0"); return INIT_PARAMETERS_INCORRECT; }
   if(InpORCA_UmbralScore <= 0.0 || InpORCA_UmbralScore > 1.0)
      { Alert("Error: InpORCA_UmbralScore debe estar entre 0.01 y 1.0"); return INIT_PARAMETERS_INCORRECT; }

   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetAsyncMode(false);
   g_Trade.SetTypeFilling(DetectFillingType());
   g_PipSize = _Point * 10.0;

   Print("════════════════════════════════════════════");
   Print("  ORB EA v3.00 ORCA XAUUSD — Iniciando");
   Print("════════════════════════════════════════════");
   PrintFormat("  Sesion    : %02d:%02d  |  Rango: %d velas", InpSessionHour, InpSessionMinute, InpRangeCandles);
   PrintFormat("  SL=%.1f | TP=%.1f | BE=%.1f (pips)", InpSL_Pips, InpTP_Pips, InpBE_Pips);
   PrintFormat("  ORCA activo: %s | PesoBullPressure=%.2f | UmbralScore=%.3f",
               InpORCA_Activo ? "SI" : "NO", InpORCA_PesoBullPressure, InpORCA_UmbralScore);
   PrintFormat("  Magic #: %d | Riesgo: %s", InpMagicNumber,
               InpUsePercentRisk ? StringFormat("%.2f%%", InpRiskPercent) : StringFormat("$%.2f", InpRiskUSD));

   if(InpShowVisuals) DrawPanelInfo("INICIANDO");
   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| OnDeinit                                                         |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   CancelAllPendingOrders();
   DeleteAllObjects();
   Comment("");
   PrintFormat("ORB EA v3 ORCA detenido. Razon: %d", reason);
}

//+------------------------------------------------------------------+
//| OnTick                                                           |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime    now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   if(dt.day != g_PrevDay)
   {
      ResetDay(now, dt.day_of_week);
      g_PrevDay = dt.day;
   }

   if(!IsDayAllowed(dt.day_of_week))
   {
      if(InpShowVisuals) DrawPanelInfo("DIA NO PERMITIDO");
      return;
   }

   if(g_TradeDone)
   {
      if(InpShowVisuals) DrawPanelInfo("COMPLETADO");
      return;
   }

   if(!g_RangeBuilt)
   {
      if(now < g_RangeEndTime)
      {
         if(InpShowVisuals) DrawPanelInfo("DEFINIENDO RANGO...");
         return;
      }
      if(BuildRangeConORCA()) // BuildRange + ORCA integrado
      {
         g_RangeBuilt = true;
         PrintFormat("RANGO DEFINIDO | H=%.5f L=%.5f | ORCA_Score=%.4f (BP=%.4f MB=%.4f)",
                     g_RangeHigh, g_RangeLow, g_ORCA_Score, g_ORCA_BullPressure, g_ORCA_MidBias);
         if(InpShowVisuals)
         {
            DrawSessionLine();
            DrawRangeLevels();
            ColorRangeCandles();
         }
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRangeConORCA: sin velas validas. Saltando dia.");
         g_TradeDone = true;
         if(InpShowVisuals) DrawPanelInfo("SIN RANGO VALIDO");
      }
      return;
   }

   if(g_OrdersPlaced) ManageTrade();
   if(InpShowVisuals) DrawPanelInfo(GetStatusStr());
}

//+------------------------------------------------------------------+
//| BuildRangeConORCA — construye el rango ORB y calcula ORCA        |
//|  Combina BuildRange() y CalcularORCA() en un solo recorrido      |
//|  para maxima eficiencia: solo se itera las velas una vez.        |
//+------------------------------------------------------------------+
bool BuildRangeConORCA()
{
   double hi          = 0.0;
   double lo          = DBL_MAX;
   int    count       = 0;
   int    total       = iBars(_Symbol, _Period);
   double firstOpen   = 0.0;       // Primera apertura del rango
   double bpSum       = 0.0;       // Acumulador BullPressure
   int    bpCount     = 0;         // Velas validas para BP

   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);
      if(t >= g_RangeEndTime)  continue;
      if(t < g_RangeStartTime) break;

      double o = iOpen (_Symbol, _Period, i);
      double h = iHigh (_Symbol, _Period, i);
      double l = iLow  (_Symbol, _Period, i);
      double c = iClose(_Symbol, _Period, i);

      // Acumular High/Low del rango
      if(h > hi) hi = h;
      if(l < lo) lo = l;

      // Primera apertura = la del extremo cronologico (mayor indice = mas antigua)
      firstOpen = o; // se sobreescribe, queda la mas antigua

      // BullPressure: ratio cuerpo sobre rango de la vela
      double velaRange = h - l;
      if(velaRange > _Point * 5) // ignorar dojis
      {
         bpSum += (c - o) / velaRange;
         bpCount++;
      }
      count++;
   }

   PrintFormat("BuildRangeConORCA: %d vela(s) en [%s - %s]", count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));

   if(count == 0 || hi <= lo || hi == 0.0) return false;

   g_RangeHigh = hi;
   g_RangeLow  = lo;

   // --- Calcular ORCA si esta activo ---
   g_ORCA_Score       = 0.0;
   g_ORCA_BullPressure = 0.0;
   g_ORCA_MidBias     = 0.0;

   if(InpORCA_Activo && bpCount > 0)
   {
      // Componente 1: BullPressure medio [-1, +1]
      g_ORCA_BullPressure = bpSum / (double)bpCount;

      // Componente 2: MidBias — sesgo del midpoint respecto a primera apertura
      double rangeMid  = (g_RangeHigh + g_RangeLow) * 0.5;
      double amplitude = g_RangeHigh - g_RangeLow;
      if(amplitude > _Point * 10)
         g_ORCA_MidBias = (rangeMid - firstOpen) / amplitude;
      g_ORCA_MidBias = MathMax(-1.0, MathMin(1.0, g_ORCA_MidBias));

      // Score compuesto ponderado
      double pesoMB = 1.0 - InpORCA_PesoBullPressure;
      g_ORCA_Score  = InpORCA_PesoBullPressure * g_ORCA_BullPressure
                    + pesoMB                   * g_ORCA_MidBias;
      g_ORCA_Score  = MathMax(-1.0, MathMin(1.0, g_ORCA_Score));
   }

   return true;
}

//+------------------------------------------------------------------+
//| ResetDay                                                         |
//+------------------------------------------------------------------+
void ResetDay(datetime now, int dayOfWeek)
{
   CancelAllPendingOrders();
   DeleteDayObjects();
   g_RangeHigh         = 0.0;
   g_RangeLow          = 0.0;
   g_RangeBuilt        = false;
   g_OrdersPlaced      = false;
   g_TradeDone         = false;
   g_BEApplied         = false;
   g_OppCancelled      = false;
   g_TicketBuy         = 0;
   g_TicketSell        = 0;
   g_ORCA_Score        = 0.0;
   g_ORCA_BullPressure  = 0.0;
   g_ORCA_MidBias      = 0.0;

   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight + InpSessionHour * 3600 + InpSessionMinute * 60;
   g_RangeEndTime       = g_RangeStartTime + (long)InpRangeCandles * PeriodSeconds(_Period);

   if(IsDayAllowed(dayOfWeek))
      PrintFormat("Nuevo dia | Sesion: %s -> Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
}

//+------------------------------------------------------------------+
//| PlacePendingOrders — aplica filtro ORCA + InpTradeDirection      |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   bool baseAllowBuy  = (InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY);
   bool baseAllowSell = (InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY);
   bool finalAllowBuy  = baseAllowBuy;
   bool finalAllowSell = baseAllowSell;

   if(InpORCA_Activo)
   {
      // Score > +umbral: presion alcista dominante -> bloquear SELL
      if(g_ORCA_Score >  InpORCA_UmbralScore) finalAllowSell = false;
      // Score < -umbral: presion bajista dominante -> bloquear BUY
      if(g_ORCA_Score < -InpORCA_UmbralScore) finalAllowBuy  = false;
      // Zona neutra: respetar InpTradeDirection sin cambios
      PrintFormat("ORCA filtro | Score=%.4f (BP=%.4f MB=%.4f) | Umbral=%.3f | BUY=%s SELL=%s",
                  g_ORCA_Score, g_ORCA_BullPressure, g_ORCA_MidBias, InpORCA_UmbralScore,
                  finalAllowBuy ? "SI" : "NO", finalAllowSell ? "SI" : "NO");
   }

   if(!finalAllowBuy && !finalAllowSell)
   {
      Print("ORCA: ninguna direccion permitida para hoy. Saltando.");
      g_TradeDone = true;
      return;
   }

   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist  = InpSL_Pips * g_PipSize;
   double tpDist  = InpTP_Pips * g_PipSize;
   double minDist = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots    = CalculateLotSize();
   bool   placed  = false;

   if(lots <= 0.0) { Print("PlacePendingOrders: lotaje invalido."); g_TradeDone=true; return; }

   if(finalAllowBuy && g_RangeHigh > ask + minDist)
   {
      double entry=NormalizeDouble(g_RangeHigh,_Digits);
      double sl=NormalizeDouble(entry-slDist,_Digits); double tp=NormalizeDouble(entry+tpDist,_Digits);
      if(g_Trade.BuyStop(lots,entry,_Symbol,sl,tp,ORDER_TIME_GTC,0,InpComment))
      { g_TicketBuy=g_Trade.ResultOrder();
        PrintFormat("BUY STOP #%s E=%.5f SL=%.5f TP=%.5f Lots=%.2f",(string)g_TicketBuy,entry,sl,tp,lots);
        placed=true; }
      else PrintFormat("Error BUY STOP: %s (%d)",g_Trade.ResultRetcodeDescription(),g_Trade.ResultRetcode());
   }
   else if(finalAllowBuy) PrintFormat("BUY STOP omitido: precio cerca del High");

   if(finalAllowSell && g_RangeLow < bid - minDist)
   {
      double entry=NormalizeDouble(g_RangeLow,_Digits);
      double sl=NormalizeDouble(entry+slDist,_Digits); double tp=NormalizeDouble(entry-tpDist,_Digits);
      if(g_Trade.SellStop(lots,entry,_Symbol,sl,tp,ORDER_TIME_GTC,0,InpComment))
      { g_TicketSell=g_Trade.ResultOrder();
        PrintFormat("SELL STOP #%s E=%.5f SL=%.5f TP=%.5f Lots=%.2f",(string)g_TicketSell,entry,sl,tp,lots);
        placed=true; }
      else PrintFormat("Error SELL STOP: %s (%d)",g_Trade.ResultRetcodeDescription(),g_Trade.ResultRetcode());
   }
   else if(finalAllowSell) PrintFormat("SELL STOP omitido: precio cerca del Low");

   g_OrdersPlaced = placed;
   if(!placed) { Print("Sin ordenes colocadas. Dia terminado."); g_TradeDone=true; }
}

//+------------------------------------------------------------------+
//| ManageTrade                                                      |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();
   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      { CancelAllPendingOrders(); g_OppCancelled=true;
        PrintFormat("Breakout activado! #%s",(string)posTicket);
        if(InpShowVisuals) DrawTradeLevels(posTicket); }
      if(!g_BEApplied && InpBE_Pips>0.0) ApplyBreakeven(posTicket);
      return;
   }
   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay) { g_TradeDone=true; DeleteTradeLines(); Print("Dia completado."); }
      else { g_OppCancelled=false; g_BEApplied=false; g_TicketBuy=0; g_TicketSell=0; DeleteTradeLines(); PlacePendingOrders(); }
      return;
   }
   bool bP=(g_TicketBuy>0&&IsOrderPending(g_TicketBuy)); bool sP=(g_TicketSell>0&&IsOrderPending(g_TicketSell));
   if(!bP&&!sP) { g_TradeDone=true; Print("Ordenes expiradas. Dia terminado."); }
}

//+------------------------------------------------------------------+
//| ApplyBreakeven                                                   |
//+------------------------------------------------------------------+
void ApplyBreakeven(ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;
   ENUM_POSITION_TYPE pt=(ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   double op=PositionGetDouble(POSITION_PRICE_OPEN); double cSL=PositionGetDouble(POSITION_SL);
   double cTP=PositionGetDouble(POSITION_TP); double beDist=InpBE_Pips*g_PipSize;
   double bid=SymbolInfoDouble(_Symbol,SYMBOL_BID); double ask=SymbolInfoDouble(_Symbol,SYMBOL_ASK);
   double newSL=0.0; bool doMod=false;
   if(pt==POSITION_TYPE_BUY) { if(bid>=op+beDist) { newSL=NormalizeDouble(op,_Digits); if(newSL>cSL) doMod=true; } }
   else { if(ask<=op-beDist) { newSL=NormalizeDouble(op,_Digits); if(cSL==0.0||newSL<cSL) doMod=true; } }
   if(doMod)
   {
      if(g_Trade.PositionModify(ticket,newSL,cTP))
      { g_BEApplied=true; PrintFormat("BE aplicado #%s SL=%.5f",(string)ticket,newSL); if(InpShowVisuals) DrawBELine(newSL); }
      else PrintFormat("Error BE: %s (%d)",g_Trade.ResultRetcodeDescription(),g_Trade.ResultRetcode());
   }
}

//+------------------------------------------------------------------+
//| CalculateLotSize                                                 |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance=AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount=InpUsePercentRisk?(balance*InpRiskPercent/100.0):InpRiskUSD;
   double tickValue=SymbolInfoDouble(_Symbol,SYMBOL_TRADE_TICK_VALUE);
   double tickSize=SymbolInfoDouble(_Symbol,SYMBOL_TRADE_TICK_SIZE);
   if(tickSize<=0.0||tickValue<=0.0) return 0.0;
   double vpp=tickValue*(g_PipSize/tickSize); if(vpp<=0.0) return 0.0;
   double lots=riskAmount/(InpSL_Pips*vpp);
   double minL=SymbolInfoDouble(_Symbol,SYMBOL_VOLUME_MIN); double maxL=SymbolInfoDouble(_Symbol,SYMBOL_VOLUME_MAX);
   double step=SymbolInfoDouble(_Symbol,SYMBOL_VOLUME_STEP);
   lots=MathFloor(lots/step)*step; lots=MathMax(lots,minL); lots=MathMin(lots,maxL);
   return lots;
}

