//+------------------------------------------------------------------+
//| ManageTrade                                                      |
//|  Logica de estados:                                              |
//|   CASO 1: posicion abierta -> gestionar normalmente (BE, etc.)  |
//|   CASO 2: posicion cerrada post-activacion -> dia completado    |
//|   CASO 3: ambas ordenes pendientes -> verificar timer de        |
//|           expiracion. Si vencio, cancelar AMBAS y cerrar dia.   |
//|           Si una ya no existe pero no hay posicion, significa   |
//|           que ambas expiraron externamente -> cerrar dia.       |
//|                                                                  |
//|  REGLA FUNDAMENTAL: si al menos UNA orden se activo (hay        |
//|   posicion abierta = CASO 1, o hubo posicion = CASO 2),         |
//|   el timer de expiracion NO aplica bajo ninguna circunstancia.  |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();

   // ─── CASO 1: Posicion abierta ────────────────────────────────────
   // Una orden se activo. Timer irrelevante. Gestionar normalmente.
   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      {
         CancelAllPendingOrders();
         g_OppCancelled = true;
         Print("Breakout activado! Posicion #", (string)posTicket, " | Orden opuesta cancelada.");
         if(InpShowVisuals) DrawTradeLevels(posTicket);
      }
      if(!g_BEApplied && InpBE_Pips > 0.0)
         ApplyBreakeven(posTicket);
      return;
   }

   // ─── CASO 2: Posicion cerrada (vino de activacion previa) ────────
   // El trade ya termino (por TP, SL o BE). Timer irrelevante.
   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay)
      {
         g_TradeDone = true;
         DeleteTradeLines();
         Print("Posicion cerrada. Dia completado.");
      }
      else
      {
         g_OppCancelled = false;
         g_BEApplied    = false;
         g_TicketBuy    = 0;
         g_TicketSell   = 0;
         g_OrdenesColocadasTime = 0;
         DeleteTradeLines();
         PlacePendingOrders();
      }
      return;
   }

   // ─── CASO 3: Sin posicion, sin activacion previa ─────────────────
   // Ambas ordenes siguen pendientes (o desaparecieron sin activarse).
   // Aqui aplica el timer de expiracion InpOrdenExpiraVelas.

   bool buyPending  = (g_TicketBuy  > 0 && IsOrderPending(g_TicketBuy));
   bool sellPending = (g_TicketSell > 0 && IsOrderPending(g_TicketSell));

   // Sub-caso 3a: ambas ordenes desaparecieron sin generar posicion
   if(!buyPending && !sellPending)
   {
      g_TradeDone = true;
      Print("Ordenes expiradas/canceladas sin activacion. Dia terminado.");
      return;
   }

   // Sub-caso 3b: verificar timer de expiracion
   // Solo actua si InpOrdenExpiraVelas > 0 y el timestamp esta registrado
   // y AMBAS ordenes siguen pendientes (si una falta hay estado inconsistente
   // que se resolvera en el siguiente tick o en sub-caso 3a)
   if(InpOrdenExpiraVelas > 0 && g_OrdenesColocadasTime > 0 && buyPending && sellPending)
   {
      long segundosTrans = (long)(TimeCurrent() - g_OrdenesColocadasTime);
      long velasTrans    = segundosTrans / (long)PeriodSeconds(_Period);
      long velasRestantes = (long)InpOrdenExpiraVelas - velasTrans;

      if(velasTrans >= (long)InpOrdenExpiraVelas)
      {
         // Timer vencido — AMBAS ordenes siguen pendientes sin activarse.
         // Cancelar las dos y cerrar el dia.
         PrintFormat("TIMER EXPIRADO | %d/%d velas transcurridas | Cancelando AMBAS ordenes pendientes.",
                     velasTrans, InpOrdenExpiraVelas);
         CancelAllPendingOrders();
         g_TradeDone = true;
         if(InpShowVisuals) DrawPanelInfo("EXPIRADO SIN ACTIVACION");
      }
      // Si no vencio, no hacer nada — seguir esperando
   }
}

