//|   + g_OrdenesColocadasTime — timestamp de colocacion            |
//|   + ManageTrade() — verifica expiracion antes de cualquier      |
//|     otra logica cuando ambas ordenes siguen pendientes          |
//|   + Panel visual muestra countdown de velas restantes           |
//+------------------------------------------------------------------+
#property copyright   "Jose's Trading Suite"
#property link        ""
#property version     "2.10"
#property description "ORB EA v2.1 XAUUSD - Con ventana de expiracion de ordenes"

