//+------------------------------------------------------------------+
//|  ENUM DE DIRECCION                                               |
//+------------------------------------------------------------------+
enum ENUM_ORB_DIRECTION
{
   DIR_BOTH      = 0,  // Ambos — BUY STOP + SELL STOP
   DIR_BUY_ONLY  = 1,  // Solo compras — BUY STOP en el High
   DIR_SELL_ONLY = 2   // Solo ventas  — SELL STOP en el Low
};

//+------------------------------------------------------------------+
//|  PARAMETROS DE ENTRADA                                           |
//+------------------------------------------------------------------+

input group "=== CONFIGURACION DEL RANGO ORB ==="
input int     InpRangeCandles    = 4;            // Numero de velas del rango inicial
input int     InpSessionHour     = 17;           // Hora inicio sesion (hora servidor GMT)
input int     InpSessionMinute   = 0;            // Minutos inicio sesion

input group "=== GESTION DE RIESGO ==="
input double  InpTP_Pips         = 130.0;        // Take Profit (pips)
input double  InpSL_Pips         = 60.0;         // Stop Loss (pips)
input double  InpBE_Pips         = 0.0;          // Breakeven trigger (pips, 0 = desactivado)
input double  InpRiskUSD         = 25.0;         // Riesgo en USD por operacion
input bool    InpUsePercentRisk  = false;         // Usar % del balance en lugar de USD
input double  InpRiskPercent     = 1.0;          // Riesgo en % si UsePercentRisk = true

input group "=== DIAS PERMITIDOS ==="
input bool    InpAllowMonday     = true;          // Lunes
input bool    InpAllowTuesday    = false;         // Martes
input bool    InpAllowWednesday  = false;         // Miercoles
input bool    InpAllowThursday   = false;         // Jueves
input bool    InpAllowFriday     = true;          // Viernes
input bool    InpAllowSaturday   = false;         // Sabado
input bool    InpAllowSunday     = false;         // Domingo

input group "=== CONFIGURACION GENERAL ==="
input ENUM_ORB_DIRECTION InpTradeDirection = DIR_BOTH; // Direccion: Ambos/Solo Compras/Solo Ventas
input bool    InpOnlyOnePerDay   = true;          // Solo un trade por dia
input int     InpMagicNumber     = 20260401;      // Magic Number unico del EA
input string  InpComment         = "ORB_v2_XAU"; // Comentario de las ordenes

input group "=== VENTANA DE EXPIRACION DE ORDENES ==="
input int     InpOrdenExpiraVelas = 24;           // Velas M5 desde colocacion tras las que expiran AMBAS ordenes si ninguna se activo (0=sin limite)

input group "=== VISUALIZACION ==="
input bool    InpShowVisuals     = true;          // Activar objetos visuales en el grafico
input color   InpColorTP         = clrLime;       // Color linea TP
input color   InpColorSL         = clrRed;        // Color linea SL
input color   InpColorBE         = clrCyan;       // Color linea BE
input color   InpColorRange      = clrOrange;     // Color velas rango ORB
input color   InpColorSession    = clrWhite;      // Color linea vertical sesion

//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES — LOGICA                                     |
//+------------------------------------------------------------------+
CTrade   g_Trade;
double   g_PipSize        = 0.0;
int      g_PrevDay        = -1;
