const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType, LevelFormat
} = require('docx');
const fs = require('fs');

// ── Colores ──────────────────────────────────────────────────────────
const BLUE      = "1F4E79";
const BLUE_MID  = "2E75B6";
const BLUE_LT   = "BDD7EE";
const GREEN_BG  = "E2EFDA";
const GREEN_TXT = "375623";
const RED_BG    = "FCE4D6";
const RED_TXT   = "833C00";
const AMB_BG    = "FFF2CC";
const AMB_TXT   = "7F6000";
const INFO_BG   = "DEEAF1";
const INFO_TXT  = "1F4E79";
const CYAN_BG   = "E0F7F7";
const CYAN_TXT  = "006666";
const GRAY_BG   = "F2F2F2";
const WHITE     = "FFFFFF";
const W         = 9360; // ancho contenido

// ── Bordes ───────────────────────────────────────────────────────────
const b1 = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const bd = { top: b1, bottom: b1, left: b1, right: b1 };
const nb = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const nbd = { top: nb, bottom: nb, left: nb, right: nb };

// ── Helpers ───────────────────────────────────────────────────────────
const sp = (sz=120) => new Paragraph({ spacing:{before:sz,after:0}, children:[new TextRun("")] });

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 300, after: 140 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: BLUE_MID, space: 1 } },
    children: [new TextRun({ text, bold: true, size: 28, font: "Arial", color: BLUE })]
  });
}
function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 200, after: 100 },
    children: [new TextRun({ text, bold: true, size: 24, font: "Arial", color: BLUE_MID })]
  });
}
function p(text, opts={}) {
  return new Paragraph({
    spacing: { before: 60, after: 80 },
    children: [new TextRun({ text, size: 20, font: "Arial", ...opts })]
  });
}
function bullet(text) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, size: 20, font: "Arial" })]
  });
}
function numbered(text) {
  return new Paragraph({
    numbering: { reference: "numbers", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, size: 20, font: "Arial" })]
  });
}

function callout(title, body, bg, tc) {
  return new Table({
    width: { size: W, type: WidthType.DXA }, columnWidths: [W],
    rows: [new TableRow({ children: [new TableCell({
      borders: bd, shading: { fill: bg, type: ShadingType.CLEAR },
      margins: { top:100, bottom:100, left:200, right:200 },
      width: { size: W, type: WidthType.DXA },
      children: [
        new Paragraph({ spacing:{after:60}, children:[new TextRun({ text: title, bold:true, size:20, font:"Arial", color:tc })] }),
        new Paragraph({ spacing:{before:0}, children:[new TextRun({ text: body, size:19, font:"Arial", color:"333333" })] }),
      ]
    })})]
  });
}

function tbl2(rows, colW=[2800,6560], hdr=null) {
  const mkC = (txt, bg, bold, clr, w) => new TableCell({
    borders: bd, width:{ size:w, type:WidthType.DXA },
    shading:{ fill: bg||WHITE, type:ShadingType.CLEAR },
    margins:{ top:80, bottom:80, left:120, right:120 },
    children:[new Paragraph({ children:[new TextRun({ text:txt, bold:!!bold, size:19, font:"Arial", color:clr||"000000" })] })]
  });
  const tableRows = [];
  if(hdr) tableRows.push(new TableRow({ tableHeader:true, children:[
    new TableCell({ borders:bd, width:{size:colW[0],type:WidthType.DXA}, shading:{fill:BLUE,type:ShadingType.CLEAR}, margins:{top:80,bottom:80,left:120,right:120}, children:[new Paragraph({children:[new TextRun({text:hdr[0],bold:true,size:20,font:"Arial",color:WHITE})]})] }),
    new TableCell({ borders:bd, width:{size:colW[1],type:WidthType.DXA}, shading:{fill:BLUE,type:ShadingType.CLEAR}, margins:{top:80,bottom:80,left:120,right:120}, children:[new Paragraph({children:[new TextRun({text:hdr[1],bold:true,size:20,font:"Arial",color:WHITE})]})] }),
  ]}));
  rows.forEach(([c1,c2,bg1,bg2,b1,b2,clr1,clr2]) => {
    tableRows.push(new TableRow({ children:[mkC(c1,bg1,b1,clr1,colW[0]), mkC(c2,bg2,b2,clr2,colW[1])] }));
  });
  return new Table({ width:{size:W,type:WidthType.DXA}, columnWidths:colW, rows:tableRows });
}

function tbl3(rows, colW=[1800,3780,3780], hdr=null) {
  const mkC = (txt,bg,bold,clr,w) => new TableCell({
    borders:bd, width:{size:w,type:WidthType.DXA},
    shading:{fill:bg||WHITE,type:ShadingType.CLEAR},
    margins:{top:80,bottom:80,left:120,right:120},
    children:[new Paragraph({children:[new TextRun({text:txt,bold:!!bold,size:19,font:"Arial",color:clr||"000000"})]})]
  });
  const tableRows=[];
  if(hdr) tableRows.push(new TableRow({ tableHeader:true, children:colW.map((w,i)=>
    new TableCell({borders:bd,width:{size:w,type:WidthType.DXA},shading:{fill:BLUE,type:ShadingType.CLEAR},margins:{top:80,bottom:80,left:120,right:120},children:[new Paragraph({children:[new TextRun({text:hdr[i],bold:true,size:20,font:"Arial",color:WHITE})]})]}))
  }));
  rows.forEach(r => {
    tableRows.push(new TableRow({children:r.map((cell,i)=>{
      const txt=typeof cell==='string'?cell:cell.text;
      const bg=typeof cell==='object'?cell.bg:null;
      const bold=typeof cell==='object'?cell.bold:false;
      const clr=typeof cell==='object'?cell.clr:null;
      return mkC(txt,bg,bold,clr,colW[i]);
    })}));
  });
  return new Table({width:{size:W,type:WidthType.DXA},columnWidths:colW,rows:tableRows});
}

// ── DOCUMENTO ─────────────────────────────────────────────────────────
const doc = new Document({
  numbering: { config: [
    { reference:"bullets", levels:[{level:0,format:LevelFormat.BULLET,text:"\u2022",alignment:AlignmentType.LEFT,style:{paragraph:{indent:{left:600,hanging:300}}}}] },
    { reference:"numbers", levels:[{level:0,format:LevelFormat.DECIMAL,text:"%1.",alignment:AlignmentType.LEFT,style:{paragraph:{indent:{left:600,hanging:300}}}}] },
  ]},
  styles: { default: { document: { run: { font:"Arial", size:20 } } } },
  sections: [{ properties: { page: { size:{width:12240,height:15840}, margin:{top:1080,right:1080,bottom:1080,left:1080} } },
  children: [

    // ── PORTADA ──────────────────────────────────────────────────────
    new Paragraph({ alignment:AlignmentType.CENTER, spacing:{before:0,after:80},
      children:[new TextRun({text:"ORB Breakout EA — Versión 2b (v2.1)", bold:true, size:44, font:"Arial", color:BLUE})] }),
    new Paragraph({ alignment:AlignmentType.CENTER, spacing:{before:0,after:60},
      children:[new TextRun({text:"XAUUSD M5 — Con ventana de expiración de órdenes", size:24, font:"Arial", color:"555555"})] }),
    new Paragraph({ alignment:AlignmentType.CENTER, spacing:{before:0,after:40},
      border:{ bottom:{style:BorderStyle.SINGLE,size:6,color:BLUE_MID,space:1} },
      children:[new TextRun({text:"Jose's Trading Suite  |  Abril 2026  |  MQL5 / MT5  |  FundingPips", size:18, font:"Arial", color:"777777"})] }),
    sp(200),

    // ── 1. IDENTIDAD DEL ARCHIVO ─────────────────────────────────────
    h1("1. Identidad del archivo"),
    tbl2([
      ["Nombre del archivo",  "ORB_BreakoutEA_v2b_XAUUSD.mq5",          GRAY_BG, WHITE, true],
      ["Versión",             "#property version \"2.10\"",               GRAY_BG, WHITE],
      ["Versión anterior",    "v2.0 — ORB_BreakoutEA_v2_XAUUSD.mq5",    GRAY_BG, WHITE],
      ["Símbolo",             "XAUUSD  |  Timeframe M5",                  GRAY_BG, WHITE],
      ["Magic Number",        "20260401",                                  GRAY_BG, WHITE],
      ["Comentario órdenes",  "ORB_v2_XAU",                               GRAY_BG, WHITE],
      ["Prefijo objetos",     "ORB_v2_XAU_  (idéntico a v2.0)",           GRAY_BG, WHITE],
      ["Líneas de código",    "995 líneas",                                GRAY_BG, WHITE],
      ["Frase de edge",       "El borde no esta en cada vela — esta en las 1000 operaciones.", AMB_BG, WHITE, false, false, null, AMB_TXT],
    ], [2800,6560], ["Campo","Valor"]),
    sp(),

    // ── 2. QUE ES LA V2B ─────────────────────────────────────────────
    h1("2. Qué es la v2b y por qué existe"),
    p("La v2b es la v2.0 con un único cambio funcional: una ventana de expiración de órdenes controlada por el parámetro InpOrdenExpiraVelas. El resto del código — lógica ORB, sistema visual, cálculo de lotaje, breakeven — es idéntico a v2.0."),
    sp(80),
    callout(
      "Hipótesis que motivó el cambio",
      "Si el breakout no ocurre en las primeras N velas M5 tras colocar las órdenes, el mercado entró en consolidación. Las órdenes GTC que permanecen activas durante horas pueden activarse en condiciones de baja liquidez o movimientos de cierre de sesión, fuera del contexto institucional que el ORB pretende capturar. Cancelar ambas órdenes si ninguna se activa en la ventana designada elimina ese riesgo.",
      INFO_BG, INFO_TXT
    ),
    sp(),

    // ── 3. PARAMETROS COMPLETOS ──────────────────────────────────────
    h1("3. Parámetros de entrada completos"),
    h2("3.1 Configuración del rango ORB"),
    tbl2([
      ["InpRangeCandles",  "4 — Velas M5 del rango inicial (default NY set validado)", GRAY_BG, WHITE, true],
      ["InpSessionHour",   "17 — Hora inicio sesión en hora del servidor",              GRAY_BG, WHITE, true],
      ["InpSessionMinute", "0 — Minutos del inicio de sesión",                          GRAY_BG, WHITE, true],
    ], [2800,6560], ["Parámetro","Valor default y descripción"]),
    sp(80),
    h2("3.2 Gestión de riesgo"),
    tbl2([
      ["InpTP_Pips",       "130.0 — Take Profit en pips. RR 2.17:1 con SL=60",         GREEN_BG, WHITE, true, false, GREEN_TXT],
      ["InpSL_Pips",       "60.0 — Stop Loss en pips",                                 RED_BG,   WHITE, true, false, RED_TXT],
      ["InpBE_Pips",       "0.0 — Breakeven trigger en pips. 0 = desactivado",         GRAY_BG,  WHITE, true],
      ["InpRiskUSD",       "25.0 — Riesgo fijo en USD por operación (validado IS/OOS)", AMB_BG,  WHITE, true, false, AMB_TXT],
      ["InpUsePercentRisk","false — Si true, usa % del balance en lugar de USD fijo",  GRAY_BG,  WHITE, true],
      ["InpRiskPercent",   "1.0 — % del balance si InpUsePercentRisk=true",            GRAY_BG,  WHITE, true],
    ], [2800,6560], ["Parámetro","Valor default y descripción"]),
    sp(80),
    h2("3.3 Días permitidos"),
    tbl2([
      ["InpAllowMonday",    "true  ★ — Lunes: PF validado 1.33 IS / 1.35 OOS",         GREEN_BG, WHITE, true, false, GREEN_TXT],
      ["InpAllowTuesday",   "false — Martes: PF 0.77 IS (destructivo)",                RED_BG,   WHITE, true, false, RED_TXT],
      ["InpAllowWednesday", "false — Miércoles: PF 0.83 IS (negativo)",                RED_BG,   WHITE, true, false, RED_TXT],
      ["InpAllowThursday",  "false — Jueves: sin borde validado",                      GRAY_BG,  WHITE, true],
      ["InpAllowFriday",    "true  ★ — Viernes: PF validado 1.40 IS / 1.53 OOS",      GREEN_BG, WHITE, true, false, GREEN_TXT],
      ["InpAllowSaturday",  "false — Mercado cerrado",                                 GRAY_BG,  WHITE],
      ["InpAllowSunday",    "false — Mercado cerrado",                                 GRAY_BG,  WHITE],
    ], [2800,6560], ["Parámetro","Configuración NY validada"]),
    sp(80),
    h2("3.4 Configuración general"),
    tbl2([
      ["InpTradeDirection", "DIR_BOTH (0) — BUY STOP + SELL STOP simultáneos",        GRAY_BG, WHITE, true],
      ["InpOnlyOnePerDay",  "true — Un solo trade por día (modo conservador)",         GRAY_BG, WHITE, true],
      ["InpMagicNumber",    "20260401 — Identificador único del EA",                  GRAY_BG, WHITE, true],
      ["InpComment",        "\"ORB_v2_XAU\" — Comentario en las órdenes",            GRAY_BG, WHITE, true],
    ], [2800,6560], ["Parámetro","Valor y descripción"]),
    sp(80),

    // ── PARAMETRO NUEVO ──────────────────────────────────────────────
    h2("3.5 Ventana de expiración de órdenes — NUEVO en v2b"),
    callout(
      "InpOrdenExpiraVelas  (int, default = 24)",
      "Número de velas M5 transcurridas desde que PlacePendingOrders() colocó las órdenes BUY STOP y SELL STOP, tras las cuales el EA cancela AMBAS si ninguna se activó. Con 24 velas M5 = 120 minutos = 2 horas de ventana. 0 = sin límite (comportamiento idéntico a v2.0).",
      CYAN_BG, CYAN_TXT
    ),
    sp(80),
    callout(
      "Regla fundamental — inmutable en el código",
      "Si UNA orden se activa (hay posición abierta), el timer queda completamente inactivo. La posición sigue su curso normal con TP, SL y BE sin ninguna interferencia del timer. El EA solo cancela si AMBAS órdenes siguen pendientes al vencer InpOrdenExpiraVelas. Jamás cancela una posición ya abierta.",
      GREEN_BG, GREEN_TXT
    ),
    sp(80),
    tbl2([
      ["Valor 0",   "Sin límite — comportamiento idéntico a v2.0. Órdenes GTC hasta fin de día o activación.", GRAY_BG, WHITE, true],
      ["Valor 12",  "60 minutos de ventana. Para sesiones muy activas (Londres, NY) donde el impulso inicial dura ~1 hora.", INFO_BG, WHITE, true, false, INFO_TXT],
