    sp(80),
    tbl2([
      ["Condición",                      "Texto mostrado en panel",               GRAY_BG, WHITE, true],
      ["Timer activo, tiempo suficiente", "Expira : N velas (M min) — gris",      GRAY_BG, WHITE],
      ["Timer activo, menos de 60 min",   "Expira : N velas (M min) — amarillo",  AMB_BG,  WHITE, false, false, null, AMB_TXT],
      ["Timer activo, menos de 30 min",   "Expira : N velas (M min) — rojo",      RED_BG,  WHITE, false, false, null, RED_TXT],
      ["Timer vencido",                   "Expira : VENCIDO",                     RED_BG,  WHITE, false, false, null, RED_TXT],
      ["InpOrdenExpiraVelas = 0",         "Expira : SIN LIMITE — gris apagado",   GRAY_BG, WHITE],
      ["Sin órdenes colocadas",           "Expira : --",                          GRAY_BG, WHITE],
    ], [3200,6160], ["Condición","Texto en panel"]),
    sp(),

    // ── 7. GRIDS DE OPTIMIZACION ─────────────────────────────────────
    h1("7. Grids de optimización pendientes"),
    h2("7.1 Sesión Asiática — 04:00 GMT (hora servidor calibrar)"),
    callout(
      "IS: 2022-01-01 → 2025-03-31  |  OOS (Forward): 2025-04-01 → 2026-03-31",
      "Mismos períodos para ambas sesiones — comparación justa sin sesgo temporal.",
      INFO_BG, INFO_TXT
    ),
