{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType, LevelFormat
} = require('docx');
const fs = require('fs');

// ── Colores ──────────────────────────────────────────────────────────
const BLUE      = "1F4E79";
const BLUE_MID  = "2E75B6";
