const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType, LevelFormat
} = require('docx');
const fs = require('fs');

const BLUE     = "1F4E79"; const BLUE_MID = "2E75B6"; const BLUE_LT  = "BDD7EE";
const GREEN_BG = "E2EFDA"; const GREEN_TXT= "375623"; const RED_BG   = "FCE4D6";
const RED_TXT  = "833C00"; const AMB_BG   = "FFF2CC"; const AMB_TXT  = "7F6000";
const INFO_BG  = "DEEAF1"; const INFO_TXT = "1F4E79"; const CYAN_BG  = "E0F7F7";
const CYAN_TXT = "006666"; const GRAY_BG  = "F2F2F2"; const WHITE    = "FFFFFF";
const PURP_BG  = "EDE7F6"; const PURP_TXT = "4527A0"; const W = 9360;

const b1  = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const bd  = { top: b1, bottom: b1, left: b1, right: b1 };
const nb  = { style: BorderStyle.NONE,   size: 0, color: "FFFFFF" };
const nbd = { top: nb, bottom: nb, left: nb, right: nb };

const sp = (sz=120) => new Paragraph({ spacing:{before:sz,after:0}, children:[new TextRun("")] });

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1, spacing:{before:280,after:120},
    border:{ bottom:{style:BorderStyle.SINGLE,size:6,color:BLUE_MID,space:1} },
    children:[new TextRun({text,bold:true,size:28,font:"Arial",color:BLUE})]
  });
}
function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2, spacing:{before:200,after:100},
    children:[new TextRun({text,bold:true,size:24,font:"Arial",color:BLUE_MID})]
  });
}
function h3(text) {
  return new Paragraph({
    spacing:{before:160,after:80},
    children:[new TextRun({text,bold:true,size:21,font:"Arial",color:"2E4057"})]
  });
}
function p(text, opts={}) {
  return new Paragraph({
    spacing:{before:60,after:80},
    children:[new TextRun({text,size:20,font:"Arial",...opts})]
  });
}
function bullet(text) {
  return new Paragraph({
    numbering:{reference:"bullets",level:0}, spacing:{before:40,after:40},
    children:[new TextRun({text,size:20,font:"Arial"})]
  });
}
function numbered(text) {
  return new Paragraph({
    numbering:{reference:"numbers",level:0}, spacing:{before:40,after:40},
    children:[new TextRun({text,size:20,font:"Arial"})]
  });
}
function callout(title, body, bg, tc) {
  return new Table({
    width:{size:W,type:WidthType.DXA}, columnWidths:[W],
    rows:[new TableRow({children:[new TableCell({
      borders:bd, shading:{fill:bg,type:ShadingType.CLEAR},
      margins:{top:100,bottom:100,left:200,right:200}, width:{size:W,type:WidthType.DXA},
      children:[
        new Paragraph({spacing:{after:60},children:[new TextRun({text:title,bold:true,size:20,font:"Arial",color:tc})]}),
        new Paragraph({spacing:{before:0},children:[new TextRun({text:body,size:19,font:"Arial",color:"333333"})]}),
      ]
    })]})]
  });
}
function tbl2(rows,colW=[2800,6560],hdr=null){
  const mkC=(txt,bg,bold,clr,w)=>new TableCell({
    borders:bd,width:{size:w,type:WidthType.DXA},shading:{fill:bg||WHITE,type:ShadingType.CLEAR},
    margins:{top:80,bottom:80,left:120,right:120},
    children:[new Paragraph({children:[new TextRun({text:txt,bold:!!bold,size:19,font:"Arial",color:clr||"000000"})]})]
  });
  const tableRows=[];
  if(hdr) tableRows.push(new TableRow({tableHeader:true,children:[
    new TableCell({borders:bd,width:{size:colW[0],type:WidthType.DXA},shading:{fill:BLUE,type:ShadingType.CLEAR},margins:{top:80,bottom:80,left:120,right:120},children:[new Paragraph({children:[new TextRun({text:hdr[0],bold:true,size:20,font:"Arial",color:WHITE})]})] }),
    new TableCell({borders:bd,width:{size:colW[1],type:WidthType.DXA},shading:{fill:BLUE,type:ShadingType.CLEAR},margins:{top:80,bottom:80,left:120,right:120},children:[new Paragraph({children:[new TextRun({text:hdr[1],bold:true,size:20,font:"Arial",color:WHITE})]})] }),
  ]}));
  rows.forEach(([c1,c2,bg1,bg2,b1f,b2f,clr1,clr2])=>{
    tableRows.push(new TableRow({children:[mkC(c1,bg1,b1f,clr1,colW[0]),mkC(c2,bg2,b2f,clr2,colW[1])]}));
  });
  return new Table({width:{size:W,type:WidthType.DXA},columnWidths:colW,rows:tableRows});
}
function tbl3(rows,colW=[1600,2400,5360],hdr=null){
  const mkC=(txt,bg,bold,clr,w)=>new TableCell({
    borders:bd,width:{size:w,type:WidthType.DXA},shading:{fill:bg||WHITE,type:ShadingType.CLEAR},
    margins:{top:80,bottom:80,left:120,right:120},
    children:[new Paragraph({children:[new TextRun({text:txt,bold:!!bold,size:19,font:"Arial",color:clr||"000000"})]})]
  });
  const tableRows=[];
  if(hdr) tableRows.push(new TableRow({tableHeader:true,children:colW.map((w,i)=>
    new TableCell({borders:bd,width:{size:w,type:WidthType.DXA},shading:{fill:BLUE,type:ShadingType.CLEAR},margins:{top:80,bottom:80,left:120,right:120},children:[new Paragraph({children:[new TextRun({text:hdr[i],bold:true,size:20,font:"Arial",color:WHITE})]})]}))
  }));
  rows.forEach(r=>{
    tableRows.push(new TableRow({children:r.map((cell,i)=>{
      const txt=typeof cell==='string'?cell:cell.text;
      const bg=typeof cell==='object'?cell.bg:null;
      const bold=typeof cell==='object'?cell.bold:false;
      const clr=typeof cell==='object'?cell.clr:null;
      return mkC(txt,bg,bold,clr,colW[i]);
    })}));
  });
  return new Table({width:{size:W,type:WidthType.DXA},columnWidths:colW,rows:tableRows});
}

// ─────────────────────────────────────────────────────────────────────
const doc = new Document({
  numbering:{config:[
    {reference:"bullets",levels:[{level:0,format:LevelFormat.BULLET,text:"\u2022",alignment:AlignmentType.LEFT,style:{paragraph:{indent:{left:600,hanging:300}}}}]},
